toolUseResult.originalFile:
package checker

import (
	"fmt"

	"github.com/135yshr/meow/pkg/ast"
	"github.com/135yshr/meow/pkg/token"
	"github.com/135yshr/meow/pkg/types"
)

// TypeInfo stores resolved type information for AST nodes.
type TypeInfo struct {
	ExprTypes   map[ast.Expr]types.Type
	VarTypes    map[string]types.Type
	FuncTypes   map[string]types.FuncType
	KittyTypes  map[string]types.KittyType
	AliasTypes  map[string]types.AliasType
	CollarTypes map[string]types.CollarType
	TrickTypes  map[string]types.TrickType
	LearnImpls  map[string]map[string]types.FuncType // typeName → methodName → FuncType
	ImportNames map[string]string                     // effective name → package path
}

// NewTypeInfo creates an empty TypeInfo.
func NewTypeInfo() *TypeInfo {
	return &TypeInfo{
		ExprTypes:   make(map[ast.Expr]types.Type),
		VarTypes:    make(map[string]types.Type),
		FuncTypes:   make(map[string]types.FuncType),
		KittyTypes:  make(map[string]types.KittyType),
		AliasTypes:  make(map[string]types.AliasType),
		CollarTypes: make(map[string]types.CollarType),
		TrickTypes:  make(map[string]types.TrickType),
		LearnImpls:  make(map[string]map[string]types.FuncType),
		ImportNames: make(map[string]string),
	}
}

// TypeError represents a type checking error.
type TypeError struct {
	Pos     token.Position
	Message string
}

func (e *TypeError) Error() string {
	return fmt.Sprintf("Hiss! %s at %s, nya~", e.Message, e.Pos)
}

// Checker performs type checking on a Meow AST.
type Checker struct {
	info              *TypeInfo
	errors            []*TypeError
	scopes            []map[string]types.Type
	currentReturnType types.Type // return type of the function currently being checked
}

// New creates a new Checker.
func New() *Checker {
	c := &Checker{
		info: NewTypeInfo(),
	}
	c.pushScope()
	return c
}

func (c *Checker) pushScope() {
	c.scopes = append(c.scopes, make(map[string]types.Type))
}

func (c *Checker) popScope() {
	c.scopes = c.scopes[:len(c.scopes)-1]
}

func (c *Checker) define(name string, t types.Type) {
	c.scopes[len(c.scopes)-1][name] = t
}

func (c *Checker) lookup(name string) types.Type {
	for i := len(c.scopes) - 1; i >= 0; i-- {
		if t, ok := c.scopes[i][name]; ok {
			return t
		}
	}
	return types.AnyType{}
}

func (c *Checker) addError(pos token.Position, format string, args ...any) {
	c.errors = append(c.errors, &TypeError{
		Pos:     pos,
		Message: fmt.Sprintf(format, args...),
	})
}

// Check type-checks a program and returns type info and any errors.
func (c *Checker) Check(prog *ast.Program) (*TypeInfo, []*TypeError) {
	// Pre-pass: register import names and check for import-import collisions
	for _, stmt := range prog.Stmts {
		if fs, ok := stmt.(*ast.FetchStmt); ok {
			effectiveName := fs.Path
			if fs.Alias != "" {
				effectiveName = fs.Alias
			}
			if prevPath, exists := c.info.ImportNames[effectiveName]; exists {
				c.addError(fs.Token.Pos,
					"import name '%s' already used for package %q", effectiveName, prevPath)
			} else {
				c.info.ImportNames[effectiveName] = fs.Path
			}
		}
	}

	// First pass: register type/function names as placeholders
	for _, stmt := range prog.Stmts {
		if bs, ok := stmt.(*ast.BreedStmt); ok {
			c.info.AliasTypes[bs.Name] = types.AliasType{Name: bs.Name, Underlying: types.AnyType{}}
		}
		if cs, ok := stmt.(*ast.CollarStmt); ok {
			c.info.CollarTypes[cs.Name] = types.CollarType{Name: cs.Name, Underlying: types.AnyType{}}
		}
		if ks, ok := stmt.(*ast.KittyStmt); ok {
			c.info.KittyTypes[ks.Name] = types.KittyType{Name: ks.Name}
		}
		if ts, ok := stmt.(*ast.TrickStmt); ok {
			c.info.TrickTypes[ts.Name] = types.TrickType{Name: ts.Name}
		}
		if fn, ok := stmt.(*ast.FuncStmt); ok {
			ft := c.funcSignatureType(fn)
			c.info.FuncTypes[fn.Name] = ft
			c.define(fn.Name, ft)
		}
	}

	// Check for collisions between import names and top-level definitions
	for _, stmt := range prog.Stmts {
		var defName string
		var pos token.Position
		switch s := stmt.(type) {
		case *ast.VarStmt:
			defName = s.Name
			pos = s.Token.Pos
		case *ast.FuncStmt:
			defName = s.Name
			pos = s.Token.Pos
		case *ast.KittyStmt:
			defName = s.Name
			pos = s.Token.Pos
		case *ast.BreedStmt:
			defName = s.Name
			pos = s.Token.Pos
		case *ast.CollarStmt:
			defName = s.Name
			pos = s.Token.Pos
		case *ast.TrickStmt:
			defName = s.Name
			pos = s.Token.Pos
		}
		if defName == "" {
			continue
		}
		if pkgPath, exists := c.info.ImportNames[defName]; exists {
			c.addError(pos,
				"'%s' shadows imported package %q; use tag to rename the import (e.g., nab %q tag %s)",
				defName, pkgPath, pkgPath, defName[:1])
		}
	}

	// Second pass: resolve underlying types (forward references now work)
	for _, stmt := range prog.Stmts {
		if bs, ok := stmt.(*ast.BreedStmt); ok {
			at := c.info.AliasTypes[bs.Name]
			at.Underlying = c.resolveTypeExpr(bs.Original)
			c.info.AliasTypes[bs.Name] = at
		}
		if cs, ok := stmt.(*ast.CollarStmt); ok {
			ct := c.info.CollarTypes[cs.Name]
			ct.Underlying = c.resolveTypeExpr(cs.Wrapped)
			c.info.CollarTypes[cs.Name] = ct
		}
		if ks, ok := stmt.(*ast.KittyStmt); ok {
			fields := make([]types.KittyFieldType, len(ks.Fields))
			for i, f := range ks.Fields {
				fields[i] = types.KittyFieldType{Name: f.Name, Type: c.resolveTypeExpr(f.TypeAnn)}
			}
			kt := c.info.KittyTypes[ks.Name]
			kt.Fields = fields
			c.info.KittyTypes[ks.Name] = kt
		}
		if ts, ok := stmt.(*ast.TrickStmt); ok {
			methods := make([]types.TrickMethodSig, len(ts.Methods))
			for i, m := range ts.Methods {
				paramTypes := make([]types.Type, len(m.Params))
				for j, p := range m.Params {
					paramTypes[j] = c.resolveTypeExpr(p.TypeAnn)
				}
				methods[i] = types.TrickMethodSig{
					Name:       m.Name,
					ParamTypes: paramTypes,
					ReturnType: c.resolveTypeExpr(m.ReturnType),
				}
			}
			tt := c.info.TrickTypes[ts.Name]
			tt.Methods = methods
			c.info.TrickTypes[ts.Name] = tt
		}
	}

	// Fixup: refresh stale alias/collar references from forward declarations.
	// When breed A = B was resolved before breed B = int, A's underlying holds
	// a stale copy of B. Replace it with the latest from the map.
	// Both AliasType and CollarType snapshots can become stale, so we check
	// both wrapper kinds in each entry.
	maxIter := len(c.info.AliasTypes) + len(c.info.CollarTypes)
	for i := 0; i < maxIter; i++ {
		changed := false
		for name, at := range c.info.AliasTypes {
			if refreshed, ok := c.refreshUnderlying(at.Underlying); ok {
				at.Underlying = refreshed
				c.info.AliasTypes[name] = at
				changed = true
			}
		}
		for name, ct := range c.info.CollarTypes {
			if refreshed, ok := c.refreshUnderlying(ct.Underlying); ok {
				ct.Underlying = refreshed
				c.info.CollarTypes[name] = ct
				changed = true
			}
		}
		if !changed {
			break
		}
	}

	// Third pass: check all statements
	for _, stmt := range prog.Stmts {
		c.checkStmt(stmt)
	}

	if len(c.errors) > 0 {
		return c.info, c.errors
	}
	return c.info, nil
}

// refreshUnderlying checks if t is a stale AliasType or CollarType snapshot
// and returns the latest version from the map. Returns (latest, true) if
// refreshed, or (nil, false) if no update is needed.
func (c *Checker) refreshUnderlying(t types.Type) (types.Type, bool) {
	switch inner := t.(type) {
	case types.AliasType:
		if latest, found := c.info.AliasTypes[inner.Name]; found {
			if !inner.Underlying.Equals(latest.Underlying) {
				return latest, true
			}
		}
	case types.CollarType:
		if latest, found := c.info.CollarTypes[inner.Name]; found {
			if !inner.Underlying.Equals(latest.Underlying) {
				return latest, true
			}
		}
	}
	return nil, false
}

func (c *Checker) funcSignatureType(fn *ast.FuncStmt) types.FuncType {
	params := make([]types.Type, len(fn.Params))
	for i, p := range fn.Params {
		params[i] = c.resolveTypeExpr(p.TypeAnn)
	}
	ret := c.resolveTypeExpr(fn.ReturnType)
	return types.FuncType{Params: params, Return: ret}
}

func (c *Checker) resolveTypeExpr(te ast.TypeExpr) types.Type {
	if te == nil {
		return types.AnyType{}
	}
	switch t := te.(type) {
	case *ast.BasicType:
		switch t.Name {
		case "int":
			return types.IntType{}
		case "float":
			return types.FloatType{}
		case "string":
			return types.StringType{}
		case "bool":
			return types.BoolType{}
		case "furball":
			return types.FurballType{}
		case "litter":
			return types.ListType{Elem: types.AnyType{}}
		default:
			return types.AnyType{}
		}
	case *ast.NamedType:
		if at, ok := c.info.AliasTypes[t.Name]; ok {
			return at
		}
		if ct, ok := c.info.CollarTypes[t.Name]; ok {
			return ct
		}
		if kt, ok := c.info.KittyTypes[t.Name]; ok {
			return kt
		}
		c.addError(t.Token.Pos, "Unknown type %s", t.Name)
		return types.AnyType{}
	default:
		return types.AnyType{}
	}
}

func (c *Checker) checkStmt(stmt ast.Stmt) {
	switch s := stmt.(type) {
	case *ast.VarStmt:
		c.checkVarStmt(s)
	case *ast.FuncStmt:
		c.checkFuncStmt(s)
	case *ast.ReturnStmt:
		c.checkReturnStmt(s)
	case *ast.IfStmt:
		c.checkIfStmt(s)
	case *ast.RangeStmt:
		c.checkRangeStmt(s)
	case *ast.ExprStmt:
		c.inferExpr(s.Expr)
	case *ast.FetchStmt:
		// nothing to check
	case *ast.KittyStmt:
		// already registered in first pass
	case *ast.BreedStmt:
		// already registered in first pass
	case *ast.CollarStmt:
		// already registered in first pass
	case *ast.TrickStmt:
		// already registered in first/second pass
	case *ast.LearnStmt:
		c.checkLearnStmt(s)
	}
}

func (c *Checker) checkLearnStmt(s *ast.LearnStmt) {
	// Verify the target type exists
	_, isKitty := c.info.KittyTypes[s.TypeName]
	_, isCollar := c.info.CollarTypes[s.TypeName]
	if !isKitty && !isCollar {
		c.addError(s.Token.Pos, "groom target %s is not a known kitty or collar type", s.TypeName)
		return
	}

	if c.info.LearnImpls[s.TypeName] == nil {
		c.info.LearnImpls[s.TypeName] = make(map[string]types.FuncType)
	}

	for i := range s.Methods {
		m := &s.Methods[i]

		// Mirror function-level signature checks
		for _, p := range m.Params {
			if p.TypeAnn == nil {
				c.addError(m.Token.Pos, "Parameter %q of method %s must have a type annotation", p.Name, m.Name)
			}
		}
		if m.ReturnType == nil && hasReturnStmt(m.Body) {
			c.addError(m.Token.Pos, "Method %s has bring statements but no return type annotation", m.Name)
		}
		methodReturnType := c.resolveTypeExpr(m.ReturnType)
		if !types.IsAny(methodReturnType) && !blockAlwaysReturns(m.Body) {
			c.addError(m.Token.Pos, "Method %s declares return type %s but does not return on all paths",
				m.Name, methodReturnType)
		}

		// Check for duplicate method names
		if _, exists := c.info.LearnImpls[s.TypeName][m.Name]; exists {
			c.addError(m.Token.Pos, "duplicate method %s for type %s", m.Name, s.TypeName)
			continue
		}

		// Type check the method body with self in scope
		prevReturnType := c.currentReturnType
		c.currentReturnType = methodReturnType

		c.pushScope()
		// Register self as the target type
		if isKitty {
			c.define("self", c.info.KittyTypes[s.TypeName])
		} else {
			c.define("self", c.info.CollarTypes[s.TypeName])
		}
		for _, p := range m.Params {
			pt := c.resolveTypeExpr(p.TypeAnn)
			c.define(p.Name, pt)
		}
		for _, stmt := range m.Body {
			c.checkStmt(stmt)
		}
		c.popScope()
		c.currentReturnType = prevReturnType

		// Register the method signature
		paramTypes := make([]types.Type, len(m.Params))
		for j, p := range m.Params {
			paramTypes[j] = c.resolveTypeExpr(p.TypeAnn)
		}
		ft := types.FuncType{
			Params: paramTypes,
			Return: methodReturnType,
		}
		c.info.LearnImpls[s.TypeName][m.Name] = ft
	}
}

func (c *Checker) checkVarStmt(s *ast.VarStmt) {
	valType := c.inferExpr(s.Value)
	declType := c.resolveTypeExpr(s.TypeAnn)

	// Reject same-scope redeclaration (shadowing in inner scopes is allowed)
	if s.Name != "_" {
		currentScope := c.scopes[len(c.scopes)-1]
		if _, exists := currentScope[s.Name]; exists {
			c.addError(s.Token.Pos, "Variable %s already declared in this scope", s.Name)
		}
	}

	if !types.IsAny(declType) && !types.IsAny(valType) {
		if !declType.Equals(valType) {
			c.addError(s.Token.Pos, "Variable %s declared as %s but assigned %s", s.Name, declType, valType)
		}
	}

	if !types.IsAny(declType) {
		c.define(s.Name, declType)
		c.info.VarTypes[s.Name] = declType
	} else {
		c.define(s.Name, valType)
		c.info.VarTypes[s.Name] = valType
	}
}

func (c *Checker) checkFuncStmt(fn *ast.FuncStmt) {
	// Enforce type annotations on all parameters
	for _, p := range fn.Params {
		if p.TypeAnn == nil {
			c.addError(fn.Token.Pos, "Parameter %q of function %s must have a type annotation", p.Name, fn.Name)
		}
	}

	// Enforce return type when function has bring statements
	if fn.ReturnType == nil && hasReturnStmt(fn.Body) {
		c.addError(fn.Token.Pos, "Function %s has bring statements but no return type annotation", fn.Name)
	}

	prevReturnType := c.currentReturnType
	c.currentReturnType = c.resolveTypeExpr(fn.ReturnType)

	// Typed functions must return on all paths
	if !types.IsAny(c.currentReturnType) && !blockAlwaysReturns(fn.Body) {
		c.addError(fn.Token.Pos, "Function %s declares return type %s but does not return on all paths",
			fn.Name, c.currentReturnType)
	}

	c.pushScope()
	for _, p := range fn.Params {
		pt := c.resolveTypeExpr(p.TypeAnn)
		c.define(p.Name, pt)
	}
	for _, stmt := range fn.Body {
		c.checkStmt(stmt)
	}
	c.popScope()

	c.currentReturnType = prevReturnType
}

// isPrimitiveType reports whether t is a simple scalar type (int, float, string, bool, nil).
func isPrimitiveType(t types.Type) bool {
	switch t.(type) {
	case types.IntType, types.FloatType, types.StringType, types.BoolType, types.NilType:
		return true
	default:
		return false
	}
}

// blockAlwaysReturns checks if all control-flow paths end with a return statement.
func blockAlwaysReturns(stmts []ast.Stmt) bool {
	if len(stmts) == 0 {
		return false
	}
	switch s := stmts[len(stmts)-1].(type) {
	case *ast.ReturnStmt:
		return true
	case *ast.IfStmt:
		return blockAlwaysReturns(s.Body) && blockAlwaysReturns(s.ElseBody)
	default:
		return false
	}
}

// hasReturnStmt checks whether a slice of statements contains any ReturnStmt (bring).
func hasReturnStmt(stmts []ast.Stmt) bool {
	for _, stmt := range stmts {
		switch s := stmt.(type) {
		case *ast.ReturnStmt:
			return true
		case *ast.IfStmt:
			if hasReturnStmt(s.Body) || hasReturnStmt(s.ElseBody) {
				return true
			}
		case *ast.RangeStmt:
			if hasReturnStmt(s.Body) {
				return true
			}
		}
	}
	return false
}

func (c *Checker) checkReturnStmt(s *ast.ReturnStmt) {
	if c.currentReturnType == nil {
		c.addError(s.Token.Pos, "bring used outside function")
		return
	}
	if s.Value == nil {
		if !types.IsAny(c.currentReturnType) {
			c.addError(s.Token.Pos, "Function requires a return value of type %s", c.currentReturnType)
		}
		return
	}
	valType := c.inferExpr(s.Value)
	if !types.IsAny(c.currentReturnType) && !types.IsAny(valType) {
		if !c.currentReturnType.Equals(valType) {
			c.addError(s.Token.Pos, "Return type mismatch: expected %s but got %s", c.currentReturnType, valType)
		}
	}
}

func (c *Checker) checkIfStmt(s *ast.IfStmt) {
	condType := types.Unwrap(c.inferExpr(s.Condition))
	if !types.IsAny(condType) {
		if _, ok := condType.(types.BoolType); !ok {
			c.addError(s.Token.Pos, "Condition must be bool, got %s", condType)
		}
	}
	c.pushScope()
	for _, stmt := range s.Body {
		c.checkStmt(stmt)
	}
	c.popScope()
	if len(s.ElseBody) > 0 {
		c.pushScope()
		for _, stmt := range s.ElseBody {
			c.checkStmt(stmt)
		}
		c.popScope()
	}
}

func (c *Checker) checkRangeStmt(s *ast.RangeStmt) {
	if s.Start != nil {
		startType := types.Unwrap(c.inferExpr(s.Start))
		if !types.IsAny(startType) {
			if _, ok := startType.(types.IntType); !ok {
				c.addError(s.Token.Pos, "Range start must be int, got %s", startType)
			}
		}
	}
	endType := types.Unwrap(c.inferExpr(s.End))
	isStringRange := false
	if !types.IsAny(endType) {
		if _, ok := endType.(types.StringType); ok && s.Start == nil && !s.Inclusive {
			isStringRange = true
		} else if _, ok := endType.(types.IntType); !ok {
			c.addError(s.Token.Pos, "Range end must be int, got %s", endType)
		}
	}
	if s.IndexVar != "" && !isStringRange {
		c.addError(s.Token.Pos, "Two-variable form is only allowed for string iteration")
	}
	c.pushScope()
	if isStringRange {
		c.define(s.Var, types.StringType{})
		c.info.VarTypes[s.Var] = types.StringType{}
		if s.IndexVar != "" {
			c.define(s.IndexVar, types.IntType{})
			c.info.VarTypes[s.IndexVar] = types.IntType{}
		}
	} else {
		c.define(s.Var, types.IntType{})
		c.info.VarTypes[s.Var] = types.IntType{}
	}
	for _, stmt := range s.Body {
		c.checkStmt(stmt)
	}
	c.popScope()
}

func (c *Checker) inferExpr(expr ast.Expr) types.Type {
	t := c.inferExprInner(expr)
	c.info.ExprTypes[expr] = t
	return t
}

func (c *Checker) inferExprInner(expr ast.Expr) types.Type {
	switch e := expr.(type) {
	case *ast.IntLit:
		return types.IntType{}
	case *ast.FloatLit:
		return types.FloatType{}
	case *ast.StringLit:
		return types.StringType{}
	case *ast.BoolLit:
		return types.BoolType{}
	case *ast.NilLit:
		return types.NilType{}
	case *ast.Ident:
		return c.lookup(e.Name)
	case *ast.UnaryExpr:
		return c.inferUnary(e)
	case *ast.BinaryExpr:
		return c.inferBinary(e)
	case *ast.CallExpr:
		return c.inferCall(e)
	case *ast.LambdaExpr:
		return c.inferLambda(e)
	case *ast.ListLit:
		return c.inferList(e)
	case *ast.IndexExpr:
		leftType := c.inferExpr(e.Left)
		c.inferExpr(e.Index)
		if lt, ok := leftType.(types.ListType); ok {
			return lt.Elem
		}
		return types.AnyType{}
	case *ast.PipeExpr:
		c.inferExpr(e.Left)
		rightType := c.inferExpr(e.Right)
		if ft, ok := rightType.(types.FuncType); ok {
			return ft.Return
		}
		return rightType
	case *ast.CatchExpr:
		leftType := c.inferExpr(e.Left)
		rightType := c.inferExpr(e.Right)
		if !types.IsAny(leftType) {
			return leftType
		}
		if ft, ok := rightType.(types.FuncType); ok {
			return ft.Return
		}
		return rightType
	case *ast.MapLit:
		for _, k := range e.Keys {
			c.inferExpr(k)
		}
		for _, v := range e.Vals {
			c.inferExpr(v)
		}
		return types.AnyType{}
	case *ast.MatchExpr:
		c.inferExpr(e.Subject)
		var armType types.Type
		for _, arm := range e.Arms {
			t := c.inferExpr(arm.Body)
			if armType == nil {
				armType = t
				continue
			}
			if !types.IsAny(armType) && !types.IsAny(t) && !armType.Equals(t) {
				c.addError(e.Token.Pos, "Match arms have inconsistent types: %s vs %s", armType, t)
				armType = types.AnyType{}
			}
		}
		if armType != nil {
			return armType
		}
		return types.AnyType{}
	case *ast.MemberExpr:
		objType := types.Unwrap(c.inferExpr(e.Object))
		if ct, ok := objType.(types.CollarType); ok {
			if e.Member == "value" {
				return ct.Underlying
			}
			// Check learn methods for collar types
			if methods, ok := c.info.LearnImpls[ct.Name]; ok {
				if _, ok := methods[e.Member]; ok {
					c.addError(e.Token.Pos, "Method %s.%s must be called with ()", ct.Name, e.Member)
					return types.AnyType{}
				}
			}
			c.addError(e.Token.Pos, "%s has no field or method %s", ct.Name, e.Member)
			return types.AnyType{}
		}
		if kt, ok := objType.(types.KittyType); ok {
			for _, f := range kt.Fields {
				if f.Name == e.Member {
					return f.Type
				}
			}
			// Check learn methods for kitty types
			if methods, ok := c.info.LearnImpls[kt.Name]; ok {
				if _, ok := methods[e.Member]; ok {
					c.addError(e.Token.Pos, "Method %s.%s must be called with ()", kt.Name, e.Member)
					return types.AnyType{}
				}
			}
			c.addError(e.Token.Pos, "%s has no field or method %s", kt.Name, e.Member)
		}
		return types.AnyType{}
	case *ast.SelfExpr:
		for i := len(c.scopes) - 1; i >= 0; i-- {
			if t, ok := c.scopes[i]["self"]; ok {
				return t
			}
		}
		c.addError(e.Token.Pos, "self can only be used inside groom methods")
		return types.AnyType{}
	default:
		return types.AnyType{}
	}
}

func (c *Checker) inferUnary(e *ast.UnaryExpr) types.Type {
	operand := c.inferExpr(e.Right)
	switch e.Op {
	case token.MINUS:
		if types.IsAny(operand) {
			return types.AnyType{}
		}
		if types.IsNumeric(types.Unwrap(operand)) {
			return operand
		}
		c.addError(e.Token.Pos, "Cannot negate %s", operand)
		return types.AnyType{}
	case token.NOT:
		// NOT operates on truthiness, so it accepts any type.
		return types.BoolType{}
	}
	return types.AnyType{}
}

func (c *Checker) inferBinary(e *ast.BinaryExpr) types.Type {
	left := c.inferExpr(e.Left)
	right := c.inferExpr(e.Right)

	// Unwrap aliases for transparent type checking
	uleft := types.Unwrap(left)
	uright := types.Unwrap(right)

	// If either side is AnyType, skip checking
	if types.IsAny(uleft) || types.IsAny(uright) {
		switch e.Op {
		case token.EQ, token.NEQ, token.LT, token.GT, token.LTE, token.GTE, token.AND, token.OR:
			return types.BoolType{}
		default:
			return types.AnyType{}
		}
	}

	switch e.Op {
	case token.PLUS:
		if uleft.Equals(uright) {
			switch uleft.(type) {
			case types.IntType, types.FloatType, types.StringType:
				return left
			}
		}
		c.addError(e.Token.Pos, "Cannot add %s and %s", left, right)
		return types.AnyType{}

	case token.MINUS, token.STAR, token.SLASH:
		if uleft.Equals(uright) && types.IsNumeric(uleft) {
			return left
		}
		op := map[token.TokenType]string{token.MINUS: "subtract", token.STAR: "multiply", token.SLASH: "divide"}
		c.addError(e.Token.Pos, "Cannot %s %s and %s", op[e.Op], left, right)
		return types.AnyType{}

	case token.PERCENT:
		if uleft.Equals(uright) {
			if _, ok := uleft.(types.IntType); ok {
				return types.IntType{}
			}
		}
		c.addError(e.Token.Pos, "Cannot modulo %s and %s", left, right)
		return types.AnyType{}

	case token.EQ, token.NEQ:
		// Allow comparison between different collar types (runtime handles it)
		_, leftIsCollar := uleft.(types.CollarType)
		_, rightIsCollar := uright.(types.CollarType)
		if !(leftIsCollar && rightIsCollar) && !uleft.Equals(uright) {
			c.addError(e.Token.Pos, "Cannot compare %s and %s", left, right)
		}
		return types.BoolType{}

	case token.LT, token.GT, token.LTE, token.GTE:
		if uleft.Equals(uright) && types.IsNumeric(uleft) {
			return types.BoolType{}
		}
		c.addError(e.Token.Pos, "Cannot compare %s and %s", left, right)
		return types.BoolType{}

	case token.AND, token.OR:
		_, lok := uleft.(types.BoolType)
		_, rok := uright.(types.BoolType)
		if !lok || !rok {
			c.addError(e.Token.Pos, "Logical operator requires bool operands, got %s and %s", left, right)
		}
		return types.BoolType{}
	}

	return types.AnyType{}
}

func (c *Checker) inferCall(e *ast.CallExpr) types.Type {
	for _, arg := range e.Args {
		c.inferExpr(arg)
	}

	if ident, ok := e.Fn.(*ast.Ident); ok {
		// Check built-in functions
		switch ident.Name {
		case "to_int":
			return types.IntType{}
		case "to_float":
			return types.FloatType{}
		case "to_string":
			return types.StringType{}
		case "is_furball":
			return types.BoolType{}
		case "len":
			return types.IntType{}
		case "nya", "hiss", "gag":
			return types.AnyType{}
		case "head":
			return types.AnyType{}
		case "tail", "append":
			return types.AnyType{}
		case "lick", "picky", "curl":
			return types.AnyType{}
		case "judge", "expect", "refuse":
			return types.AnyType{}
		}

		// Check collar constructors
		if ct, ok := c.info.CollarTypes[ident.Name]; ok {
			if len(e.Args) != 1 {
				c.addError(e.Token.Pos, "%s expects 1 argument but got %d",
					ident.Name, len(e.Args))
			} else {
				argType := c.info.ExprTypes[e.Args[0]]
				if argType != nil && !types.IsAny(argType) && !types.IsAny(ct.Underlying) {
					if !ct.Underlying.Equals(argType) {
						c.addError(e.Token.Pos, "%s expects %s but got %s",
							ident.Name, ct.Underlying, argType)
					}
				}
			}
			return ct
		}

		// Check kitty constructors
		if kt, ok := c.info.KittyTypes[ident.Name]; ok {
			if len(e.Args) != len(kt.Fields) {
				c.addError(e.Token.Pos, "%s expects %d fields but got %d",
					ident.Name, len(kt.Fields), len(e.Args))
			}
			return kt
		}

		// Check user-defined functions
		if ft, ok := c.info.FuncTypes[ident.Name]; ok {
			return c.checkFuncCall(e, ft, ident.Name)
		}

		// Check function-typed variables (partials/lambdas in scope).
		if ft, ok := types.Unwrap(c.lookup(ident.Name)).(types.FuncType); ok {
			return c.checkFuncCall(e, ft, ident.Name)
		}
	}

	// Handle member call (e.g. c.show())
	if member, ok := e.Fn.(*ast.MemberExpr); ok {
		objType := types.Unwrap(c.inferExpr(member.Object))
		typeName := ""
		switch tt := objType.(type) {
		case types.KittyType:
			typeName = tt.Name
		case types.CollarType:
			typeName = tt.Name
		}
		if typeName != "" {
			methods := c.info.LearnImpls[typeName]
			ft, ok := methods[member.Member]
			if !ok {
				c.addError(e.Token.Pos, "%s has no method %s", typeName, member.Member)
				return types.AnyType{}
			}
			if len(e.Args) != len(ft.Params) {
				c.addError(e.Token.Pos, "Method %s.%s expects %d arguments but got %d",
					typeName, member.Member, len(ft.Params), len(e.Args))
				return ft.Return
			}
			for i, arg := range e.Args {
				argType := c.info.ExprTypes[arg]
				if argType != nil && !types.IsAny(argType) && !types.IsAny(ft.Params[i]) && !ft.Params[i].Equals(argType) {
					c.addError(e.Token.Pos, "Argument %d for %s.%s: expected %s but got %s",
						i+1, typeName, member.Member, ft.Params[i], argType)
				}
			}
			return ft.Return
		}
		return types.AnyType{}
	}

	// Handle chained calls (e.g. add(1)(2)) — check if callee returns a FuncType.
	fnType := c.inferExpr(e.Fn)
	if ft, ok := types.Unwrap(fnType).(types.FuncType); ok {
		return c.checkFuncCall(e, ft, "")
	}
	return types.AnyType{}
}

// checkFuncCall validates arguments against a FuncType and returns the result type.
// For partial application (fewer args), it returns a FuncType with the remaining params.
func (c *Checker) checkFuncCall(e *ast.CallExpr, ft types.FuncType, calleeName string) types.Type {
	if len(e.Args) > len(ft.Params) {
		if calleeName != "" {
			c.addError(e.Token.Pos, "Function %s expects at most %d arguments but got %d",
				calleeName, len(ft.Params), len(e.Args))
		} else {
			c.addError(e.Token.Pos, "Function expects at most %d arguments but got %d",
				len(ft.Params), len(e.Args))
		}
		return ft.Return
	}
	for i, arg := range e.Args {
		argType := c.info.ExprTypes[arg]
		if argType != nil && !types.IsAny(argType) && !types.IsAny(ft.Params[i]) && !ft.Params[i].Equals(argType) {
			c.addError(e.Token.Pos, "Argument %d: expected %s but got %s", i+1, ft.Params[i], argType)
		}
	}
	if len(e.Args) < len(ft.Params) {
		remainingParams := make([]types.Type, len(ft.Params)-len(e.Args))
		copy(remainingParams, ft.Params[len(e.Args):])
		return types.FuncType{Params: remainingParams, Return: ft.Return}
	}
	return ft.Return
}

func (c *Checker) inferLambda(e *ast.LambdaExpr) types.Type {
	c.pushScope()
	paramTypes := make([]types.Type, len(e.Params))
	for i, p := range e.Params {
		pt := c.resolveTypeExpr(p.TypeAnn)
		paramTypes[i] = pt
		c.define(p.Name, pt)
	}
	retType := c.inferExpr(e.Body)
	c.popScope()
	return types.FuncType{Params: paramTypes, Return: retType}
}

func (c *Checker) inferList(e *ast.ListLit) types.Type {
	if len(e.Items) == 0 {
		return types.ListType{Elem: types.AnyType{}}
	}
	elemType := c.inferExpr(e.Items[0])
	for _, item := range e.Items[1:] {
		t := c.inferExpr(item)
		if !types.IsAny(elemType) && !types.IsAny(t) && !elemType.Equals(t) {
			if isPrimitiveType(elemType) && isPrimitiveType(t) {
				c.addError(e.Token.Pos, "List elements must have consistent types: %s vs %s", elemType, t)
			}
			elemType = types.AnyType{}
		}
	}
	return types.ListType{Elem: elemType}
}

package codegen

import (
	"fmt"
	"sort"
	"strings"

	"github.com/135yshr/meow/pkg/ast"
	"github.com/135yshr/meow/pkg/checker"
	"github.com/135yshr/meow/pkg/mutation"
	"github.com/135yshr/meow/pkg/token"
	"github.com/135yshr/meow/pkg/types"
)

// Generator produces Go source code from a Meow AST.
type Generator struct {
	funcs         []string
	topLevel      []string
	indent        int
	imports       map[string]string // meow pkg name → Go import path
	testMode      bool
	testFuncs     []string // names of test_ prefixed functions
	catwalkFuncs  []string // names of catwalk_ prefixed functions
	catwalkOutput CatwalkOutput
	mutations     map[ast.Expr][]mutation.MutationEntry
	coverEnabled  bool
	coverFilename string
	coverBlocks   []coverBlock
	typeInfo      *checker.TypeInfo
	currentReturnType types.Type // return type of the function currently being generated
	kittyDefs     map[string]*ast.KittyStmt
	collarDefs    map[string]*ast.CollarStmt
	learnDefs     []*ast.LearnStmt
	inLearnMethod  bool              // true when generating a learn method body
	aliasToPackage map[string]string // alias → real package name
	packageToAlias map[string]string // real package name → alias
}

type coverBlock struct {
	startLine, startCol, endLine, endCol, numStmt int
}

var stdPackages = map[string]string{
	"file":    "github.com/135yshr/meow/runtime/file",
	"http":    "github.com/135yshr/meow/runtime/http",
	"testing": "github.com/135yshr/meow/runtime/testing",
}

// resolveImportName resolves name to a real package name, considering aliases.
// Returns (realPkg, true) if the name refers to an imported package,
// or ("", false) if it does not.
func (g *Generator) resolveImportName(name string) (string, bool) {
	if rp, isAlias := g.aliasToPackage[name]; isAlias {
		return rp, true
	}
	if _, imported := g.imports[name]; imported {
		if _, hasAlias := g.packageToAlias[name]; !hasAlias {
			return name, true
		}
		return "", false
	}
	return "", false
}

// capitalizeFirst returns s with its first byte uppercased.
// Returns s unchanged if s is empty.
func capitalizeFirst(s string) string {
	if s == "" {
		return s
	}
	return strings.ToUpper(s[:1]) + s[1:]
}

// New creates a new code generator.
func New() *Generator {
	return &Generator{}
}

// NewTest creates a code generator in test mode.
func NewTest() *Generator {
	return &Generator{testMode: true}
}

// SetTypeInfo stores type checking results for use in code generation.
func (g *Generator) SetTypeInfo(ti *checker.TypeInfo) {
	g.typeInfo = ti
}

// SetCatwalkOutput sets the expected output map for catwalk_ functions.
func (g *Generator) SetCatwalkOutput(co CatwalkOutput) {
	g.catwalkOutput = co
}

// SetMutations sets the mutation schema for schemata-based mutation testing.
func (g *Generator) SetMutations(m map[ast.Expr][]mutation.MutationEntry) {
	g.mutations = m
}

// EnableCoverage activates statement coverage instrumentation.
func (g *Generator) EnableCoverage(filename string) {
	g.coverEnabled = true
	g.coverFilename = filename
}

// Generate produces Go source code from a Program AST.
func (g *Generator) Generate(prog *ast.Program) (string, error) {
	g.collectKittyDefs(prog)
	for _, stmt := range prog.Stmts {
		switch stmt.(type) {
		case *ast.KittyStmt, *ast.BreedStmt, *ast.CollarStmt, *ast.TrickStmt:
			continue
		}
		if ls, ok := stmt.(*ast.LearnStmt); ok {
			g.learnDefs = append(g.learnDefs, ls)
			for i := range ls.Methods {
				g.funcs = append(g.funcs, g.genLearnMethod(ls.TypeName, &ls.Methods[i]))
			}
			continue
		}
		if fn, ok := stmt.(*ast.FuncStmt); ok {
			g.funcs = append(g.funcs, g.genFuncDecl(fn))
		} else {
			code, err := g.genStmtOrError(stmt)
			if err != nil {
				return "", err
			}
			if code != "" {
				g.topLevel = append(g.topLevel, code)
			}
		}
	}
	return g.emit(), nil
}

// GenerateTest produces Go source code from a Program AST in test mode.
// It auto-imports the testing package and wraps test_ functions with Run/Report
// and catwalk_ functions with Catwalk.
func (g *Generator) GenerateTest(prog *ast.Program) (string, error) {
	g.collectKittyDefs(prog)
	for _, stmt := range prog.Stmts {
		switch stmt.(type) {
		case *ast.KittyStmt, *ast.BreedStmt, *ast.CollarStmt, *ast.TrickStmt:
			continue
		}
		if ls, ok := stmt.(*ast.LearnStmt); ok {
			g.learnDefs = append(g.learnDefs, ls)
			for i := range ls.Methods {
				g.funcs = append(g.funcs, g.genLearnMethod(ls.TypeName, &ls.Methods[i]))
			}
			continue
		}
		if fn, ok := stmt.(*ast.FuncStmt); ok {
			g.funcs = append(g.funcs, g.genFuncDecl(fn))
			if strings.HasPrefix(fn.Name, "test_") {
				if len(fn.Params) != 0 {
					return "", fmt.Errorf("test function %s must not take parameters", fn.Name)
				}
				g.testFuncs = append(g.testFuncs, fn.Name)
			} else if strings.HasPrefix(fn.Name, "catwalk_") {
				if len(fn.Params) != 0 {
					return "", fmt.Errorf("catwalk function %s must not take parameters", fn.Name)
				}
				if g.catwalkOutput != nil {
					if _, ok := g.catwalkOutput[fn.Name]; !ok {
						return "", fmt.Errorf("catwalk function %s has no # Output: block", fn.Name)
					}
				}
				g.catwalkFuncs = append(g.catwalkFuncs, fn.Name)
			}
		} else {
			code, err := g.genStmtOrError(stmt)
			if err != nil {
				return "", err
			}
			if code != "" {
				g.topLevel = append(g.topLevel, code)
			}
		}
	}
	g.ensureImport("testing")
	return g.emitTest(), nil
}

func (g *Generator) emitTest() string {
	var b strings.Builder
	b.WriteString("// Code generated by meow compiler. DO NOT EDIT.\n")
	b.WriteString("package main\n\n")
	b.WriteString("import meow \"github.com/135yshr/meow/runtime/meowrt\"\n")
	needsOS := g.coverEnabled || len(g.mutations) > 0
	if needsOS {
		b.WriteString("import \"os\"\n")
	}
	if len(g.mutations) > 0 {
		b.WriteString("import \"strconv\"\n")
	}
	if g.coverEnabled {
		b.WriteString("import meow_coverage \"github.com/135yshr/meow/runtime/coverage\"\n")
	}
	names := make([]string, 0, len(g.imports))
	for name := range g.imports {
		names = append(names, name)
	}
	sort.Strings(names)
	for _, name := range names {
		fmt.Fprintf(&b, "import meow_%s \"%s\"\n", name, g.imports[name])
	}
	b.WriteString("\n")

	if len(g.mutations) > 0 {
		b.WriteString("var __mutant int = -1\n\n")
	}

	needsInit := g.coverEnabled || len(g.mutations) > 0
	if needsInit {
		b.WriteString("func init() {\n")
		if len(g.mutations) > 0 {
			b.WriteString("\tif s := os.Getenv(\"MEOW_MUTANT\"); s != \"\" {\n")
			b.WriteString("\t\tif v, err := strconv.Atoi(s); err == nil {\n")
			b.WriteString("\t\t\t__mutant = v\n")
			b.WriteString("\t\t}\n")
			b.WriteString("\t}\n")
		}
		if g.coverEnabled {
			for i, cb := range g.coverBlocks {
				fmt.Fprintf(&b, "\tmeow_coverage.Register(%q, %d, %d, %d, %d, %d) // block %d\n",
					g.coverFilename, cb.startLine, cb.startCol, cb.endLine, cb.endCol, cb.numStmt, i)
			}
		}
		b.WriteString("}\n\n")
	}

	if initCode := g.genLearnInit(); initCode != "" {
		b.WriteString(initCode)
		b.WriteString("\n")
	}

	for _, fn := range g.funcs {
		b.WriteString(fn)
		b.WriteString("\n\n")
	}

	b.WriteString("func main() {\n")
	for _, line := range g.topLevel {
		b.WriteString("\t")
		b.WriteString(line)
		b.WriteString("\n")
	}
	for _, name := range g.testFuncs {
		fmt.Fprintf(&b, "\tmeow_testing.Run(meow.NewString(%q), meow.NewFunc(%q, func(args ...meow.Value) meow.Value {\n", name, name)
		fmt.Fprintf(&b, "\t\treturn %s()\n", name)
		fmt.Fprintf(&b, "\t}))\n")
	}
	for _, name := range g.catwalkFuncs {
		expected := ""
		if g.catwalkOutput != nil {
			expected = g.catwalkOutput[name]
		}
		fmt.Fprintf(&b, "\tmeow_testing.Catwalk(meow.NewString(%q), meow.NewFunc(%q, func(args ...meow.Value) meow.Value {\n", name, name)
		fmt.Fprintf(&b, "\t\treturn %s()\n", name)
		fmt.Fprintf(&b, "\t}), meow.NewString(%q))\n", expected)
	}
	if g.coverEnabled {
		b.WriteString("\tmeow_coverage.Report(os.Stdout)\n")
		b.WriteString("\tif p := os.Getenv(\"MEOW_COVERPROFILE\"); p != \"\" {\n")
		b.WriteString("\t\tmeow_coverage.WriteProfile(p)\n")
		b.WriteString("\t}\n")
	}
	b.WriteString("\tmeow_testing.Report()\n")
	b.WriteString("}\n")
	return b.String()
}

func (g *Generator) ensureImport(name string) {
	if g.imports == nil {
		g.imports = make(map[string]string)
	}
	if _, ok := g.imports[name]; !ok {
		if path, ok := stdPackages[name]; ok {
			g.imports[name] = path
		}
	}
}

func (g *Generator) needsMeowImport() bool {
	if len(g.topLevel) > 0 {
		return true
	}
	for _, fn := range g.funcs {
		if strings.Contains(fn, "meow.") {
			return true
		}
	}
	return false
}

func (g *Generator) emit() string {
	var b strings.Builder
	b.WriteString("// Code generated by meow compiler. DO NOT EDIT.\n")
	b.WriteString("package main\n\n")
	if g.needsMeowImport() {
		b.WriteString("import meow \"github.com/135yshr/meow/runtime/meowrt\"\n")
	}
	if len(g.mutations) > 0 {
		b.WriteString("import \"os\"\n")
		b.WriteString("import \"strconv\"\n")
	}
	names := make([]string, 0, len(g.imports))
	for name := range g.imports {
		names = append(names, name)
	}
	sort.Strings(names)
	for _, name := range names {
		fmt.Fprintf(&b, "import meow_%s \"%s\"\n", name, g.imports[name])
	}
	b.WriteString("\n")

	if len(g.mutations) > 0 {
		b.WriteString("var __mutant int = -1\n\n")
		b.WriteString("func init() {\n")
		b.WriteString("\tif s := os.Getenv(\"MEOW_MUTANT\"); s != \"\" {\n")
		b.WriteString("\t\tif v, err := strconv.Atoi(s); err == nil {\n")
		b.WriteString("\t\t\t__mutant = v\n")
		b.WriteString("\t\t}\n")
		b.WriteString("\t}\n")
		b.WriteString("}\n\n")
	}

	if initCode := g.genLearnInit(); initCode != "" {
		b.WriteString(initCode)
		b.WriteString("\n")
	}

	for _, fn := range g.funcs {
		b.WriteString(fn)
		b.WriteString("\n\n")
	}

	b.WriteString("func main() {\n")
	for _, line := range g.topLevel {
		b.WriteString("\t")
		b.WriteString(line)
		b.WriteString("\n")
	}
	b.WriteString("}\n")
	return b.String()
}

func (g *Generator) genFuncDecl(fn *ast.FuncStmt) string {
	if g.isFullyTypedFunc(fn) {
		return g.genTypedFuncDecl(fn)
	}
	var b strings.Builder
	params := make([]string, len(fn.Params))
	for i, p := range fn.Params {
		params[i] = p.Name + " meow.Value"
	}
	fmt.Fprintf(&b, "func %s(%s) meow.Value {\n", fn.Name, strings.Join(params, ", "))
	for _, stmt := range fn.Body {
		b.WriteString("\t")
		b.WriteString(g.genStmt(stmt))
		b.WriteString("\n")
	}
	if !g.blockAlwaysReturns(fn.Body) {
		b.WriteString("\treturn meow.NewNil()\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) isFullyTypedFunc(fn *ast.FuncStmt) bool {
	if g.typeInfo == nil {
		return false
	}
	ft, ok := g.typeInfo.FuncTypes[fn.Name]
	if !ok {
		return false
	}
	return isFullyTypedFuncType(ft)
}

func (g *Generator) genTypedFuncDecl(fn *ast.FuncStmt) string {
	ft := g.typeInfo.FuncTypes[fn.Name]
	prevReturnType := g.currentReturnType
	g.currentReturnType = ft.Return
	defer func() { g.currentReturnType = prevReturnType }()
	var b strings.Builder
	params := make([]string, len(fn.Params))
	for i, p := range fn.Params {
		params[i] = p.Name + " " + goTypeString(ft.Params[i])
	}
	fmt.Fprintf(&b, "func %s(%s) %s {\n", fn.Name, strings.Join(params, ", "), goTypeString(ft.Return))
	for _, stmt := range fn.Body {
		b.WriteString("\t")
		b.WriteString(g.genTypedStmt(stmt))
		b.WriteString("\n")
	}
	b.WriteString("}")
	return b.String()
}

func goTypeString(t types.Type) string {
	switch t := t.(type) {
	case types.IntType:
		return "int64"
	case types.FloatType:
		return "float64"
	case types.StringType:
		return "string"
	case types.BoolType:
		return "bool"
	case types.AliasType:
		return goTypeString(t.Underlying)
	default:
		return "meow.Value"
	}
}

func (g *Generator) genTypedStmt(stmt ast.Stmt) string {
	switch s := stmt.(type) {
	case *ast.VarStmt:
		return g.genTypedVarStmt(s)
	case *ast.ReturnStmt:
		return g.genTypedReturnStmt(s)
	case *ast.ExprStmt:
		return g.genTypedExprStmt(s)
	case *ast.IfStmt:
		return g.genTypedIf(s)
	case *ast.RangeStmt:
		return g.genTypedRange(s)
	default:
		return g.genStmt(stmt)
	}
}

func (g *Generator) genTypedVarStmt(s *ast.VarStmt) string {
	t := g.getExprType(s.Value)
	if t != nil && !types.IsAny(t) {
		return fmt.Sprintf("var %s %s = %s", s.Name, goTypeString(t), g.genTypedExpr(s.Value))
	}
	return fmt.Sprintf("var %s meow.Value = %s", s.Name, g.genExpr(s.Value))
}

func (g *Generator) genTypedReturnStmt(s *ast.ReturnStmt) string {
	if s.Value == nil {
		return "return"
	}
	t := g.getExprType(s.Value)
	if t != nil && !types.IsAny(t) {
		return fmt.Sprintf("return %s", g.genTypedExpr(s.Value))
	}
	// Expression is AnyType (e.g. match expression) but function has a concrete return type.
	// Generate the expression with typed boxing, then unbox the meow.Value result.
	exprCode := g.genTypedExpr(s.Value)
	if g.currentReturnType != nil && !types.IsAny(g.currentReturnType) {
		return fmt.Sprintf("return %s", unboxToNative(exprCode, g.currentReturnType))
	}
	return fmt.Sprintf("return %s", exprCode)
}

func (g *Generator) genTypedExprStmt(s *ast.ExprStmt) string {
	if call, ok := s.Expr.(*ast.CallExpr); ok {
		return g.genTypedCall(call)
	}
	return g.genExpr(s.Expr)
}

func (g *Generator) genTypedIf(s *ast.IfStmt) string {
	var b strings.Builder
	condType := g.getExprType(s.Condition)
	if condType != nil && !types.IsAny(condType) {
		fmt.Fprintf(&b, "if %s {\n", g.genTypedExpr(s.Condition))
	} else {
		fmt.Fprintf(&b, "if (%s).IsTruthy() {\n", g.genExpr(s.Condition))
	}
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genTypedStmt(stmt))
		b.WriteString("\n")
	}
	if len(s.ElseBody) > 0 {
		b.WriteString("} else {\n")
		for _, stmt := range s.ElseBody {
			b.WriteString("\t")
			b.WriteString(g.genTypedStmt(stmt))
			b.WriteString("\n")
		}
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genTypedRange(s *ast.RangeStmt) string {
	endType := g.getExprType(s.End)
	if endType != nil {
		endType = types.Unwrap(endType)
	}
	if _, ok := endType.(types.StringType); ok && s.Start == nil && !s.Inclusive {
		return g.genTypedStringRange(s)
	}
	var b strings.Builder
	cmp := "<"
	if s.Inclusive {
		cmp = "<="
	}
	startCode := "int64(0)"
	if s.Start != nil {
		startType := g.getExprType(s.Start)
		if startType != nil && !types.IsAny(startType) {
			startCode = g.genTypedExpr(s.Start)
		} else {
			startCode = ""
		}
	}
	if startCode != "" && endType != nil && !types.IsAny(endType) {
		fmt.Fprintf(&b, "for %s := %s; %s %s %s; %s++ {\n",
			s.Var, startCode, s.Var, cmp, g.genTypedExpr(s.End), s.Var)
	} else {
		startExpr := "meow.NewInt(0)"
		if s.Start != nil {
			startExpr = g.boxValue(s.Start)
		}
		fmt.Fprintf(&b, "for __i := meow.AsInt(%s); __i %s meow.AsInt(%s); __i++ {\n",
			startExpr, cmp, g.boxValue(s.End))
		fmt.Fprintf(&b, "\tvar %s int64 = __i\n", s.Var)
	}
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genTypedStmt(stmt))
		b.WriteString("\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genTypedStringRange(s *ast.RangeStmt) string {
	var b strings.Builder
	if s.IndexVar != "" {
		fmt.Fprintf(&b, "for __idx, __r := range []rune(%s) {\n",
			g.genTypedExpr(s.End))
		fmt.Fprintf(&b, "\t%s := int64(__idx)\n", s.IndexVar)
		fmt.Fprintf(&b, "\tvar %s string = string(__r)\n", s.Var)
		fmt.Fprintf(&b, "\t_ = %s\n\t_ = %s\n", s.IndexVar, s.Var)
	} else {
		fmt.Fprintf(&b, "for _, __r := range []rune(%s) {\n",
			g.genTypedExpr(s.End))
		fmt.Fprintf(&b, "\tvar %s string = string(__r)\n", s.Var)
		fmt.Fprintf(&b, "\t_ = %s\n", s.Var)
	}
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genTypedStmt(stmt))
		b.WriteString("\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) getExprType(expr ast.Expr) types.Type {
	if g.typeInfo == nil {
		return nil
	}
	return g.typeInfo.ExprTypes[expr]
}

func (g *Generator) genTypedExpr(expr ast.Expr) string {
	t := g.getExprType(expr)
	// Handle match expressions specially: they always produce meow.Value
	// but may contain typed variables that need boxing.
	if _, isMatch := expr.(*ast.MatchExpr); isMatch {
		matchCode := g.genTypedMatch(expr.(*ast.MatchExpr))
		if t != nil && isNativeType(t) {
			return unboxToNative(matchCode, t)
		}
		return matchCode
	}
	if t == nil || types.IsAny(t) {
		return g.genExprBoxed(expr)
	}
	switch e := expr.(type) {
	case *ast.IntLit:
		return fmt.Sprintf("int64(%d)", e.Value)
	case *ast.FloatLit:
		return fmt.Sprintf("float64(%g)", e.Value)
	case *ast.StringLit:
		return fmt.Sprintf("%q", e.Value)
	case *ast.BoolLit:
		if e.Value {
			return "true"
		}
		return "false"
	case *ast.Ident:
		return e.Name
	case *ast.UnaryExpr:
		return g.genTypedUnary(e)
	case *ast.BinaryExpr:
		return g.genTypedBinary(e)
	case *ast.CallExpr:
		return g.genTypedCall(e)
	default:
		return g.genExprBoxed(expr)
	}
}

// genExprBoxed generates an expression in untyped (meow.Value) mode,
// but boxes any typed variables so they can be used as meow.Value.
func (g *Generator) genExprBoxed(expr ast.Expr) string {
	if ident, ok := expr.(*ast.Ident); ok {
		t := g.getExprType(expr)
		if t != nil && !types.IsAny(t) {
			return g.boxNative(ident.Name, t)
		}
	}
	return g.genExpr(expr)
}

// boxNative wraps a native Go value in its meow.Value constructor.
func (g *Generator) boxNative(name string, t types.Type) string {
	switch types.Unwrap(t).(type) {
	case types.IntType:
		return fmt.Sprintf("meow.NewInt(%s)", name)
	case types.FloatType:
		return fmt.Sprintf("meow.NewFloat(%s)", name)
	case types.StringType:
		return fmt.Sprintf("meow.NewString(%s)", name)
	case types.BoolType:
		return fmt.Sprintf("meow.NewBool(%s)", name)
	default:
		return name
	}
}

// genTypedMatch generates a match expression where the subject may be a native type.
// It boxes the subject to meow.Value and returns the match result as meow.Value.
func (g *Generator) genTypedMatch(e *ast.MatchExpr) string {
	var b strings.Builder
	subject := g.boxValue(e.Subject)
	b.WriteString(fmt.Sprintf("func() meow.Value {\n\t__subject := %s\n", subject))
	hasCondArm := false
	for i, arm := range e.Arms {
		if _, ok := arm.Pattern.(*ast.WildcardPattern); ok {
			if hasCondArm {
				b.WriteString("\t} else {\n")
				b.WriteString(fmt.Sprintf("\t\treturn %s\n", g.boxValue(arm.Body)))
				b.WriteString("\t}\n")
			} else {
				b.WriteString(fmt.Sprintf("\treturn %s\n", g.boxValue(arm.Body)))
			}
			b.WriteString("\treturn meow.NewNil()\n}()")
			return b.String()
		}
		keyword := "if"
		if i > 0 {
			keyword = "} else if"
		}
		hasCondArm = true
		b.WriteString(fmt.Sprintf("\t%s %s {\n", keyword, g.genPatternCond("__subject", arm.Pattern)))
		b.WriteString(fmt.Sprintf("\t\treturn %s\n", g.boxValue(arm.Body)))
	}
	if hasCondArm {
		b.WriteString("\t}\n")
	}
	b.WriteString("\treturn meow.NewNil()\n}()")
	return b.String()
}

func (g *Generator) genTypedUnary(e *ast.UnaryExpr) string {
	switch e.Op {
	case token.MINUS:
		return fmt.Sprintf("(-%s)", g.genTypedExpr(e.Right))
	case token.NOT:
		if _, ok := g.getExprType(e.Right).(types.BoolType); ok {
			return fmt.Sprintf("(!%s)", g.genTypedExpr(e.Right))
		}
		return fmt.Sprintf("(!(%s).IsTruthy())", g.boxValue(e.Right))
	}
	return g.genUnary(e)
}

func (g *Generator) genTypedBinary(e *ast.BinaryExpr) string {
	left := g.genTypedExpr(e.Left)
	right := g.genTypedExpr(e.Right)
	switch e.Op {
	case token.PLUS:
		return fmt.Sprintf("(%s + %s)", left, right)
	case token.MINUS:
		return fmt.Sprintf("(%s - %s)", left, right)
	case token.STAR:
		return fmt.Sprintf("(%s * %s)", left, right)
	case token.SLASH:
		return fmt.Sprintf("(%s / %s)", left, right)
	case token.PERCENT:
		return fmt.Sprintf("(%s %% %s)", left, right)
	case token.EQ:
		return fmt.Sprintf("(%s == %s)", left, right)
	case token.NEQ:
		return fmt.Sprintf("(%s != %s)", left, right)
	case token.LT:
		return fmt.Sprintf("(%s < %s)", left, right)
	case token.GT:
		return fmt.Sprintf("(%s > %s)", left, right)
	case token.LTE:
		return fmt.Sprintf("(%s <= %s)", left, right)
	case token.GTE:
		return fmt.Sprintf("(%s >= %s)", left, right)
	case token.AND:
		return fmt.Sprintf("(%s && %s)", left, right)
	case token.OR:
		return fmt.Sprintf("(%s || %s)", left, right)
	}
	return g.genBinary(e)
}

func (g *Generator) genTypedCall(e *ast.CallExpr) string {
	// Handle method calls on learn types: unbox dispatch result if typed
	if member, ok := e.Fn.(*ast.MemberExpr); ok {
		call := g.genMemberCall(member, e.Args)
		if t := g.getExprType(e); t != nil && !types.IsAny(t) && isNativeType(t) {
			return unboxToNative(call, t)
		}
		return call
	}

	ident, isIdent := e.Fn.(*ast.Ident)
	if !isIdent {
		return g.genCall(e)
	}

	// Builtin functions that need boxing
	switch ident.Name {
	case "nya":
		args := make([]string, len(e.Args))
		for i, a := range e.Args {
			args[i] = g.boxValue(a)
		}
		return fmt.Sprintf("meow.Nya(%s)", strings.Join(args, ", "))
	case "hiss":
		args := make([]string, len(e.Args))
		for i, a := range e.Args {
			args[i] = g.boxValue(a)
		}
		return fmt.Sprintf("meow.Hiss(%s)", strings.Join(args, ", "))
	case "judge", "expect", "refuse":
		g.ensureImport("testing")
		fn := capitalizeFirst(ident.Name)
		args := make([]string, len(e.Args))
		for i, a := range e.Args {
			args[i] = g.boxValue(a)
		}
		return fmt.Sprintf("meow_testing.%s(%s)", fn, strings.Join(args, ", "))
	case "to_string", "to_int", "to_float", "is_furball", "gag", "len",
		"head", "tail", "append", "lick", "picky", "curl":
		builtinNames := map[string]string{
			"to_string":  "ToString",
			"to_int":     "ToInt",
			"to_float":   "ToFloat",
			"is_furball":  "IsFurball",
			"gag":        "Gag",
			"len":        "Len",
			"head":       "Head",
			"tail":       "Tail",
			"append":     "Append",
			"lick":       "Lick",
			"picky":      "Picky",
			"curl":       "Curl",
		}
		// Known return types for builtins that produce typed results
		builtinRetTypes := map[string]types.Type{
			"to_string":  types.StringType{},
			"to_int":     types.IntType{},
			"to_float":   types.FloatType{},
			"is_furball":  types.BoolType{},
			"len":        types.IntType{},
		}
		args := make([]string, len(e.Args))
		for i, a := range e.Args {
			args[i] = g.boxValue(a)
		}
		call := fmt.Sprintf("meow.%s(%s)", builtinNames[ident.Name], strings.Join(args, ", "))
		// If the builtin has a known return type and we're in a typed context, unbox
		if retType, ok := builtinRetTypes[ident.Name]; ok {
			return unboxToNative(call, retType)
		}
		return call
	}

	// Collar constructors
	if _, ok := g.collarDefs[ident.Name]; ok {
		args := make([]string, len(e.Args))
		for i, a := range e.Args {
			args[i] = g.boxValue(a)
		}
		return fmt.Sprintf("meow.NewKitty(%q, []string{\"value\"}, %s)",
			ident.Name, strings.Join(args, ", "))
	}

	// Typed user-defined functions (only for fully native signatures)
	if ft, ok := g.typeInfo.FuncTypes[ident.Name]; ok {
		if len(e.Args) < len(ft.Params) {
			return g.genPartialCall(ident.Name, ft, e.Args)
		}
		if isFullyTypedFuncType(ft) {
			args := make([]string, len(e.Args))
			for i, a := range e.Args {
				args[i] = g.genTypedExpr(a)
			}
			return fmt.Sprintf("%s(%s)", ident.Name, strings.Join(args, ", "))
		}
	}

	return g.genCall(e)
}

func (g *Generator) boxValue(expr ast.Expr) string {
	t := g.getExprType(expr)
	if t == nil || types.IsAny(t) {
		return g.genExpr(expr)
	}
	typed := g.genTypedExpr(expr)
	switch types.Unwrap(t).(type) {
	case types.IntType:
		return fmt.Sprintf("meow.NewInt(%s)", typed)
	case types.FloatType:
		return fmt.Sprintf("meow.NewFloat(%s)", typed)
	case types.StringType:
		return fmt.Sprintf("meow.NewString(%s)", typed)
	case types.BoolType:
		return fmt.Sprintf("meow.NewBool(%s)", typed)
	default:
		return g.genExpr(expr)
	}
}

// isNativeType reports whether t maps to a native Go type (int64, float64, string, bool).
// ListType, FurballType, and AnyType are NOT native types; they use meow.Value.
func isNativeType(t types.Type) bool {
	switch t.(type) {
	case types.IntType, types.FloatType, types.StringType, types.BoolType:
		return true
	case types.AliasType:
		return isNativeType(types.Unwrap(t))
	}
	return false
}

func isFullyTypedFuncType(ft types.FuncType) bool {
	if !isNativeType(ft.Return) {
		return false
	}
	for _, p := range ft.Params {
		if !isNativeType(p) {
			return false
		}
	}
	return true
}

func isLiteralExpr(expr ast.Expr) bool {
	switch e := expr.(type) {
	case *ast.IntLit, *ast.FloatLit, *ast.StringLit, *ast.BoolLit:
		return true
	case *ast.UnaryExpr:
		return isLiteralExpr(e.Right)
	default:
		return false
	}
}

func unboxToNative(boxedExpr string, targetType types.Type) string {
	switch types.Unwrap(targetType).(type) {
	case types.IntType:
		return fmt.Sprintf("meow.AsInt(%s)", boxedExpr)
	case types.FloatType:
		return fmt.Sprintf("meow.AsFloat(%s)", boxedExpr)
	case types.StringType:
		return fmt.Sprintf("meow.AsString(%s)", boxedExpr)
	case types.BoolType:
		return fmt.Sprintf("meow.AsBool(%s)", boxedExpr)
	default:
		return boxedExpr
	}
}

func boxNativeCall(call string, retType types.Type) string {
	switch types.Unwrap(retType).(type) {
	case types.IntType:
		return fmt.Sprintf("meow.NewInt(%s)", call)
	case types.FloatType:
		return fmt.Sprintf("meow.NewFloat(%s)", call)
	case types.StringType:
		return fmt.Sprintf("meow.NewString(%s)", call)
	case types.BoolType:
		return fmt.Sprintf("meow.NewBool(%s)", call)
	default:
		return call
	}
}

func (g *Generator) blockAlwaysReturns(stmts []ast.Stmt) bool {
	if len(stmts) == 0 {
		return false
	}
	switch s := stmts[len(stmts)-1].(type) {
	case *ast.ReturnStmt:
		return true
	case *ast.IfStmt:
		return g.blockAlwaysReturns(s.Body) && g.blockAlwaysReturns(s.ElseBody)
	default:
		return false
	}
}

func (g *Generator) genStmt(stmt ast.Stmt) string {
	code := g.genStmtInner(stmt)
	if !g.coverEnabled {
		return code
	}
	pos := stmt.Pos()
	endLine, endCol := g.estimateEndPos(stmt)
	id := len(g.coverBlocks)
	g.coverBlocks = append(g.coverBlocks, coverBlock{pos.Line, pos.Column, endLine, endCol, 1})
	return fmt.Sprintf("meow_coverage.Hit(%d)\n%s", id, code)
}

func (g *Generator) genStmtInner(stmt ast.Stmt) string {
	switch s := stmt.(type) {
	case *ast.VarStmt:
		return fmt.Sprintf("var %s meow.Value = %s", s.Name, g.genExpr(s.Value))
	case *ast.ReturnStmt:
		if s.Value != nil {
			return fmt.Sprintf("return %s", g.genExpr(s.Value))
		}
		return "return meow.NewNil()"
	case *ast.ExprStmt:
		return g.genExpr(s.Expr)
	case *ast.IfStmt:
		return g.genIf(s)
	case *ast.RangeStmt:
		return g.genRange(s)
	default:
		return fmt.Sprintf("/* unsupported stmt: %T */", stmt)
	}
}

func (g *Generator) estimateEndPos(stmt ast.Stmt) (int, int) {
	pos := stmt.Pos()
	switch s := stmt.(type) {
	case *ast.IfStmt:
		body := s.ElseBody
		if len(body) == 0 {
			body = s.Body
		}
		if len(body) > 0 {
			last := body[len(body)-1]
			endLine, _ := g.estimateEndPos(last)
			return endLine + 1, 1
		}
		return pos.Line + 1, 1
	case *ast.RangeStmt:
		if len(s.Body) > 0 {
			last := s.Body[len(s.Body)-1]
			endLine, _ := g.estimateEndPos(last)
			return endLine + 1, 1
		}
		return pos.Line + 1, 1
	default:
		return pos.Line, pos.Column + 1
	}
}

func (g *Generator) collectKittyDefs(prog *ast.Program) {
	g.kittyDefs = make(map[string]*ast.KittyStmt)
	g.collarDefs = make(map[string]*ast.CollarStmt)
	for _, stmt := range prog.Stmts {
		if ks, ok := stmt.(*ast.KittyStmt); ok {
			g.kittyDefs[ks.Name] = ks
		}
		if cs, ok := stmt.(*ast.CollarStmt); ok {
			g.collarDefs[cs.Name] = cs
		}
	}
}

func (g *Generator) genStmtOrError(stmt ast.Stmt) (string, error) {
	switch stmt.(type) {
	case *ast.KittyStmt, *ast.BreedStmt, *ast.CollarStmt, *ast.TrickStmt, *ast.LearnStmt:
		return "", nil
	}
	if s, ok := stmt.(*ast.FetchStmt); ok {
		path, ok := stdPackages[s.Path]
		if !ok {
			return "", fmt.Errorf("unknown package: %s", s.Path)
		}
		if g.imports == nil {
			g.imports = make(map[string]string)
		}
		g.imports[s.Path] = path
		if s.Alias != "" {
			if g.aliasToPackage == nil {
				g.aliasToPackage = make(map[string]string)
			}
			if g.packageToAlias == nil {
				g.packageToAlias = make(map[string]string)
			}
			g.aliasToPackage[s.Alias] = s.Path
			g.packageToAlias[s.Path] = s.Alias
		}
		return "", nil
	}
	return g.genStmt(stmt), nil
}

func (g *Generator) genIf(s *ast.IfStmt) string {
	var b strings.Builder
	fmt.Fprintf(&b, "if (%s).IsTruthy() {\n", g.genExpr(s.Condition))
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genStmt(stmt))
		b.WriteString("\n")
	}
	if len(s.ElseBody) > 0 {
		b.WriteString("} else {\n")
		for _, stmt := range s.ElseBody {
			b.WriteString("\t")
			b.WriteString(g.genStmt(stmt))
			b.WriteString("\n")
		}
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genRange(s *ast.RangeStmt) string {
	endType := g.getExprType(s.End)
	if endType != nil {
		endType = types.Unwrap(endType)
	}
	if _, ok := endType.(types.StringType); ok && s.Start == nil && !s.Inclusive {
		return g.genStringRange(s)
	}
	var b strings.Builder
	cmp := "<"
	if s.Inclusive {
		cmp = "<="
	}
	startExpr := "meow.NewInt(0)"
	if s.Start != nil {
		startExpr = g.genExpr(s.Start)
	}
	fmt.Fprintf(&b, "for __i := meow.AsInt(%s); __i %s meow.AsInt(%s); __i++ {\n",
		startExpr, cmp, g.genExpr(s.End))
	fmt.Fprintf(&b, "\tvar %s meow.Value = meow.NewInt(__i)\n", s.Var)
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genStmt(stmt))
		b.WriteString("\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genStringRange(s *ast.RangeStmt) string {
	var b strings.Builder
	if s.IndexVar != "" {
		fmt.Fprintf(&b, "for __idx, __r := range []rune(meow.AsString(%s)) {\n",
			g.genExpr(s.End))
		fmt.Fprintf(&b, "\tvar %s meow.Value = meow.NewInt(int64(__idx))\n", s.IndexVar)
		fmt.Fprintf(&b, "\tvar %s meow.Value = meow.NewString(string(__r))\n", s.Var)
		fmt.Fprintf(&b, "\t_ = %s\n\t_ = %s\n", s.IndexVar, s.Var)
	} else {
		fmt.Fprintf(&b, "for _, __r := range []rune(meow.AsString(%s)) {\n",
			g.genExpr(s.End))
		fmt.Fprintf(&b, "\tvar %s meow.Value = meow.NewString(string(__r))\n", s.Var)
		fmt.Fprintf(&b, "\t_ = %s\n", s.Var)
	}
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genStmt(stmt))
		b.WriteString("\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genExpr(expr ast.Expr) string {
	if entries, ok := g.mutations[expr]; ok && len(entries) > 0 {
		return g.genMutatedExpr(expr, entries)
	}
	switch e := expr.(type) {
	case *ast.IntLit:
		return fmt.Sprintf("meow.NewInt(%d)", e.Value)
	case *ast.FloatLit:
		return fmt.Sprintf("meow.NewFloat(%g)", e.Value)
	case *ast.StringLit:
		return fmt.Sprintf("meow.NewString(%q)", e.Value)
	case *ast.BoolLit:
		if e.Value {
			return "meow.NewBool(true)"
		}
		return "meow.NewBool(false)"
	case *ast.NilLit:
		return "meow.NewNil()"
	case *ast.Ident:
		return g.genIdent(e)
	case *ast.UnaryExpr:
		return g.genUnary(e)
	case *ast.BinaryExpr:
		return g.genBinary(e)
	case *ast.CallExpr:
		return g.genCall(e)
	case *ast.LambdaExpr:
		return g.genLambda(e)
	case *ast.ListLit:
		return g.genList(e)
	case *ast.IndexExpr:
		return g.genIndex(e)
	case *ast.PipeExpr:
		return g.genPipe(e)
	case *ast.CatchExpr:
		return g.genCatch(e)
	case *ast.MapLit:
		return g.genMap(e)
	case *ast.MatchExpr:
		return g.genMatch(e)
	case *ast.SelfExpr:
		return "self"
	case *ast.MemberExpr:
		// Check if this is a self.field access in a learn method
		if _, isSelf := e.Object.(*ast.SelfExpr); isSelf {
			if e.Member == "value" {
				return "self.(*meow.Kitty).GetField(\"value\")"
			}
			return fmt.Sprintf("self.(*meow.Kitty).GetField(%q)", e.Member)
		}
		obj, ok := e.Object.(*ast.Ident)
		if ok {
			if realPkg, ok := g.resolveImportName(obj.Name); ok {
				return fmt.Sprintf("meow_%s.%s", realPkg, capitalizeFirst(e.Member))
			}
			return fmt.Sprintf("%s.(*meow.Kitty).GetField(%q)", obj.Name, e.Member)
		}
		return fmt.Sprintf("(%s).(*meow.Kitty).GetField(%q)", g.genExpr(e.Object), e.Member)
	default:
		return fmt.Sprintf("/* unsupported expr: %T */", expr)
	}
}

func (g *Generator) genIdent(e *ast.Ident) string {
	return e.Name
}

func (g *Generator) genUnary(e *ast.UnaryExpr) string {
	switch e.Op {
	case token.MINUS:
		return fmt.Sprintf("meow.Negate(%s)", g.genExpr(e.Right))
	case token.NOT:
		return fmt.Sprintf("meow.Not(%s)", g.genExpr(e.Right))
	default:
		return fmt.Sprintf("/* unsupported unary: %v */", e.Op)
	}
}

func (g *Generator) genBinary(e *ast.BinaryExpr) string {
	l := g.genExpr(e.Left)
	r := g.genExpr(e.Right)
	switch e.Op {
	case token.PLUS:
		return fmt.Sprintf("meow.Add(%s, %s)", l, r)
	case token.MINUS:
		return fmt.Sprintf("meow.Sub(%s, %s)", l, r)
	case token.STAR:
		return fmt.Sprintf("meow.Mul(%s, %s)", l, r)
	case token.SLASH:
		return fmt.Sprintf("meow.Div(%s, %s)", l, r)
	case token.PERCENT:
		return fmt.Sprintf("meow.Mod(%s, %s)", l, r)
	case token.EQ:
		return fmt.Sprintf("meow.Equal(%s, %s)", l, r)
	case token.NEQ:
		return fmt.Sprintf("meow.NotEqual(%s, %s)", l, r)
	case token.LT:
		return fmt.Sprintf("meow.LessThan(%s, %s)", l, r)
	case token.GT:
		return fmt.Sprintf("meow.GreaterThan(%s, %s)", l, r)
	case token.LTE:
		return fmt.Sprintf("meow.LessEqual(%s, %s)", l, r)
	case token.GTE:
		return fmt.Sprintf("meow.GreaterEqual(%s, %s)", l, r)
	case token.AND:
		return fmt.Sprintf("meow.And(%s, %s)", l, r)
	case token.OR:
		return fmt.Sprintf("meow.Or(%s, %s)", l, r)
	default:
		return fmt.Sprintf("/* unsupported op: %v */", e.Op)
	}
}

func (g *Generator) genCall(e *ast.CallExpr) string {
	if member, ok := e.Fn.(*ast.MemberExpr); ok {
		return g.genMemberCall(member, e.Args)
	}
	ident, isIdent := e.Fn.(*ast.Ident)
	args := make([]string, len(e.Args))
	for i, a := range e.Args {
		args[i] = g.genExpr(a)
	}
	argStr := strings.Join(args, ", ")

	if isIdent {
		switch ident.Name {
		case "nya":
			return fmt.Sprintf("meow.Nya(%s)", argStr)
		case "hiss":
			return fmt.Sprintf("meow.Hiss(%s)", argStr)
		case "lick":
			return fmt.Sprintf("meow.Lick(%s)", argStr)
		case "picky":
			return fmt.Sprintf("meow.Picky(%s)", argStr)
		case "curl":
			return fmt.Sprintf("meow.Curl(%s)", argStr)
		case "len":
			return fmt.Sprintf("meow.Len(%s)", argStr)
		case "head":
			return fmt.Sprintf("meow.Head(%s)", argStr)
		case "tail":
			return fmt.Sprintf("meow.Tail(%s)", argStr)
		case "append":
			return fmt.Sprintf("meow.Append(%s)", argStr)
		case "to_int":
			return fmt.Sprintf("meow.ToInt(%s)", argStr)
		case "to_float":
			return fmt.Sprintf("meow.ToFloat(%s)", argStr)
		case "to_string":
			return fmt.Sprintf("meow.ToString(%s)", argStr)
		case "gag":
			return fmt.Sprintf("meow.Gag(%s)", argStr)
		case "is_furball":
			return fmt.Sprintf("meow.IsFurball(%s)", argStr)
		case "judge":
			g.ensureImport("testing")
			return fmt.Sprintf("meow_testing.Judge(%s)", argStr)
		case "expect":
			g.ensureImport("testing")
			return fmt.Sprintf("meow_testing.Expect(%s)", argStr)
		case "refuse":
			g.ensureImport("testing")
			return fmt.Sprintf("meow_testing.Refuse(%s)", argStr)
		case "seed":
			return "meow.NewNil()"
		default:
			if ks, ok := g.kittyDefs[ident.Name]; ok {
				fieldNames := make([]string, len(ks.Fields))
				for i, f := range ks.Fields {
					fieldNames[i] = fmt.Sprintf("%q", f.Name)
				}
				return fmt.Sprintf("meow.NewKitty(%q, []string{%s}, %s)",
					ident.Name, strings.Join(fieldNames, ", "), argStr)
			}
			if _, ok := g.collarDefs[ident.Name]; ok {
				return fmt.Sprintf("meow.NewKitty(%q, []string{\"value\"}, %s)",
					ident.Name, argStr)
			}
			if g.typeInfo != nil {
				if ft, ok := g.typeInfo.FuncTypes[ident.Name]; ok {
					if len(e.Args) < len(ft.Params) {
						return g.genPartialCall(ident.Name, ft, e.Args)
					}
					if len(e.Args) == len(ft.Params) && isFullyTypedFuncType(ft) {
						nativeArgs := make([]string, len(e.Args))
						for i, a := range e.Args {
							if isLiteralExpr(a) {
								nativeArgs[i] = g.genTypedExpr(a)
							} else {
								nativeArgs[i] = unboxToNative(args[i], ft.Params[i])
							}
						}
						call := fmt.Sprintf("%s(%s)", ident.Name, strings.Join(nativeArgs, ", "))
						return boxNativeCall(call, ft.Return)
					}
				} else {
					// Not in FuncTypes → must be a variable holding a function
					// value (e.g. partial application result or lambda).
					// The checker populates FuncTypes for all `meow` function
					// declarations, so any identifier absent from FuncTypes is
					// a runtime value that requires meow.Call for dispatch.
					if argStr != "" {
						return fmt.Sprintf("meow.Call(%s, %s)", ident.Name, argStr)
					}
					return fmt.Sprintf("meow.Call(%s)", ident.Name)
				}
			}
			return fmt.Sprintf("%s(%s)", ident.Name, argStr)
		}
	}
	return fmt.Sprintf("meow.Call(%s, %s)", g.genExpr(e.Fn), argStr)
}

func (g *Generator) genMemberCall(member *ast.MemberExpr, rawArgs []ast.Expr) string {
	args := make([]string, len(rawArgs))
	for i, a := range rawArgs {
		args[i] = g.genExpr(a)
	}
	argStr := strings.Join(args, ", ")

	// Check if this is a method call on an object that has learn impls
	if g.typeInfo != nil {
		objCode := g.genExpr(member.Object)
		typeName := g.resolveTypeName(member.Object)
		if typeName != "" {
			if methods, ok := g.typeInfo.LearnImpls[typeName]; ok {
				if _, hasMethod := methods[member.Member]; hasMethod {
					if argStr != "" {
						return fmt.Sprintf("meow.DispatchMethod(%s, %q, %s)", objCode, member.Member, argStr)
					}
					return fmt.Sprintf("meow.DispatchMethod(%s, %q)", objCode, member.Member)
				}
			}
		}
	}

	obj, ok := member.Object.(*ast.Ident)
	if !ok {
		if argStr == "" {
			return fmt.Sprintf("meow.Call((%s).(*meow.Kitty).GetField(%q))",
				g.genExpr(member.Object), member.Member)
		}
		return fmt.Sprintf("meow.Call((%s).(*meow.Kitty).GetField(%q), %s)",
			g.genExpr(member.Object), member.Member, argStr)
	}
	if realPkg, ok := g.resolveImportName(obj.Name); ok {
		return fmt.Sprintf("meow_%s.%s(%s)", realPkg, capitalizeFirst(member.Member), argStr)
	}
	if argStr == "" {
		return fmt.Sprintf("meow.Call(%s.(*meow.Kitty).GetField(%q))",
			obj.Name, member.Member)
	}
	return fmt.Sprintf("meow.Call(%s.(*meow.Kitty).GetField(%q), %s)",
		obj.Name, member.Member, argStr)
}

// resolveTypeName tries to determine the type name for a given expression.
func (g *Generator) resolveTypeName(expr ast.Expr) string {
	if g.typeInfo == nil {
		return ""
	}
	t := g.typeInfo.ExprTypes[expr]
	if t == nil {
		return ""
	}
	t = types.Unwrap(t)
	switch tt := t.(type) {
	case types.KittyType:
		return tt.Name
	case types.CollarType:
		return tt.Name
	}
	return ""
}

func (g *Generator) genPartialCall(fnName string, ft types.FuncType, suppliedArgs []ast.Expr) string {
	remaining := len(ft.Params) - len(suppliedArgs)

	if isFullyTypedFuncType(ft) {
		// Typed function: generate native-typed partial application
		var captureLines []string
		for i, a := range suppliedArgs {
			captureLines = append(captureLines,
				fmt.Sprintf("__c%d := %s", i, g.genTypedExpr(a)))
		}
		var callArgs []string
		for i := range suppliedArgs {
			callArgs = append(callArgs, fmt.Sprintf("__c%d", i))
		}
		for i := range remaining {
			callArgs = append(callArgs,
				fmt.Sprintf("%s", unboxToNative(fmt.Sprintf("args[%d]", i), ft.Params[len(suppliedArgs)+i])))
		}
		call := fmt.Sprintf("%s(%s)", fnName, strings.Join(callArgs, ", "))
		boxed := boxNativeCall(call, ft.Return)

		capture := strings.Join(captureLines, "\n\t")
		if capture != "" {
			capture += "\n\t"
		}
		return fmt.Sprintf("func() meow.Value {\n"+
			"\t%sreturn meow.NewFuncWithArity(%q, %d, func(args ...meow.Value) meow.Value {\n"+
			"\t\treturn %s\n"+
			"\t})\n"+
			"}()", capture, fnName, remaining, boxed)
	}

	// Untyped function: box arguments to ensure meow.Value
	var captureLines []string
	for i, a := range suppliedArgs {
		captureLines = append(captureLines,
			fmt.Sprintf("__c%d := %s", i, g.boxValue(a)))
	}
	var callArgs []string
	for i := range suppliedArgs {
		callArgs = append(callArgs, fmt.Sprintf("__c%d", i))
	}
	for i := range remaining {
		callArgs = append(callArgs, fmt.Sprintf("args[%d]", i))
	}
	call := fmt.Sprintf("%s(%s)", fnName, strings.Join(callArgs, ", "))

	capture := strings.Join(captureLines, "\n\t")
	if capture != "" {
		capture += "\n\t"
	}
	return fmt.Sprintf("func() meow.Value {\n"+
		"\t%sreturn meow.NewFuncWithArity(%q, %d, func(args ...meow.Value) meow.Value {\n"+
		"\t\treturn %s\n"+
		"\t})\n"+
		"}()", capture, fnName, remaining, call)
}

func (g *Generator) genLambda(e *ast.LambdaExpr) string {
	body := g.genExpr(e.Body)
	return fmt.Sprintf("meow.NewFuncWithArity(\"lambda\", %d, func(args ...meow.Value) meow.Value {\n"+
		"\t%s\n"+
		"\treturn %s\n"+
		"})", len(e.Params), g.genLambdaParamBindings(e.Params), body)
}

func (g *Generator) genLambdaParamBindings(params []ast.Param) string {
	var lines []string
	for i, p := range params {
		lines = append(lines, fmt.Sprintf("%s := args[%d]", p.Name, i))
		lines = append(lines, fmt.Sprintf("_ = %s", p.Name))
	}
	return strings.Join(lines, "\n\t")
}

func (g *Generator) genList(e *ast.ListLit) string {
	items := make([]string, len(e.Items))
	for i, item := range e.Items {
		items[i] = g.genExpr(item)
	}
	return fmt.Sprintf("meow.NewList(%s)", strings.Join(items, ", "))
}

func (g *Generator) genMap(e *ast.MapLit) string {
	if len(e.Keys) == 0 {
		return "meow.NewMap(map[string]meow.Value{})"
	}
	entries := make([]string, len(e.Keys))
	for i := range e.Keys {
		key, ok := e.Keys[i].(*ast.StringLit)
		if !ok {
			entries[i] = fmt.Sprintf("/* unsupported map key: %T */", e.Keys[i])
			continue
		}
		entries[i] = fmt.Sprintf("%q: %s", key.Value, g.genExpr(e.Vals[i]))
	}
	return fmt.Sprintf("meow.NewMap(map[string]meow.Value{%s})", strings.Join(entries, ", "))
}

func (g *Generator) genIndex(e *ast.IndexExpr) string {
	return fmt.Sprintf("%s.(*meow.List).Get(int(%s.(*meow.Int).Val))", g.genExpr(e.Left), g.genExpr(e.Index))
}

func (g *Generator) genPipe(e *ast.PipeExpr) string {
	var fn ast.Expr
	var args []ast.Expr

	if call, ok := e.Right.(*ast.CallExpr); ok {
		fn = call.Fn
		args = make([]ast.Expr, 0, len(call.Args)+1)
		args = append(args, e.Left)
		args = append(args, call.Args...)
	} else {
		fn = e.Right
		args = []ast.Expr{e.Left}
	}

	return g.genCall(&ast.CallExpr{Token: e.Token, Fn: fn, Args: args})
}

func (g *Generator) genCatch(e *ast.CatchExpr) string {
	left := g.genExpr(e.Left)
	right := g.genExpr(e.Right)
	return fmt.Sprintf(
		"meow.GagOr(meow.NewFunc(\"~>\", func(args ...meow.Value) meow.Value {\n"+
			"\treturn %s\n"+
			"}), %s)", left, right)
}

func (g *Generator) genMatch(e *ast.MatchExpr) string {
	var b strings.Builder
	subject := g.genExpr(e.Subject)
	b.WriteString(fmt.Sprintf("func() meow.Value {\n\t__subject := %s\n", subject))
	hasCondArm := false
	for i, arm := range e.Arms {
		if _, ok := arm.Pattern.(*ast.WildcardPattern); ok {
			if hasCondArm {
				b.WriteString("\t} else {\n")
				b.WriteString(fmt.Sprintf("\t\treturn %s\n", g.genExpr(arm.Body)))
				b.WriteString("\t}\n")
			} else {
				b.WriteString(fmt.Sprintf("\treturn %s\n", g.genExpr(arm.Body)))
			}
			b.WriteString("\treturn meow.NewNil()\n}()")
			return b.String()
		}
		keyword := "if"
		if i > 0 {
			keyword = "} else if"
		}
		hasCondArm = true
		b.WriteString(fmt.Sprintf("\t%s %s {\n", keyword, g.genPatternCond("__subject", arm.Pattern)))
		b.WriteString(fmt.Sprintf("\t\treturn %s\n", g.genExpr(arm.Body)))
	}
	if hasCondArm {
		b.WriteString("\t}\n")
	}
	b.WriteString("\treturn meow.NewNil()\n}()")
	return b.String()
}

func (g *Generator) genMutatedExpr(original ast.Expr, entries []mutation.MutationEntry) string {
	// Remove this expression's entries to avoid self-recursion
	delete(g.mutations, original)

	var b strings.Builder
	b.WriteString("func() meow.Value {\n")

	// Mutation branches: generate without child mutations
	// (each branch represents only its specific mutation, not combinations)
	saved := g.mutations
	g.mutations = nil
	for _, entry := range entries {
		fmt.Fprintf(&b, "\t\tif __mutant == %d { return %s }\n", entry.ID, g.genExpr(entry.Expr))
	}
	g.mutations = saved

	// Default branch: child mutations remain active
	fmt.Fprintf(&b, "\t\treturn %s\n", g.genExpr(original))
	b.WriteString("\t}()")

	// Restore this entry
	g.mutations[original] = entries
	return b.String()
}

func (g *Generator) genLearnMethod(typeName string, fn *ast.FuncStmt) string {
	var b strings.Builder
	methodFuncName := fmt.Sprintf("meow_method_%s_%s", typeName, fn.Name)

	fmt.Fprintf(&b, "func %s(args ...meow.Value) meow.Value {\n", methodFuncName)
	// Arity guard: self + params
	fmt.Fprintf(&b, "\tif len(args) < %d {\n", 1+len(fn.Params))
	b.WriteString("\t\treturn meow.NewNil()\n")
	b.WriteString("\t}\n")
	// Extract self from first argument
	b.WriteString("\tself := args[0]\n")
	b.WriteString("\t_ = self\n")
	// Extract additional params
	for i, p := range fn.Params {
		fmt.Fprintf(&b, "\t%s := args[%d]\n", p.Name, i+1)
		fmt.Fprintf(&b, "\t_ = %s\n", p.Name)
	}

	prevInLearn := g.inLearnMethod
	g.inLearnMethod = true
	for _, stmt := range fn.Body {
		b.WriteString("\t")
		b.WriteString(g.genStmt(stmt))
		b.WriteString("\n")
	}
	g.inLearnMethod = prevInLearn

	if !g.blockAlwaysReturns(fn.Body) {
		b.WriteString("\treturn meow.NewNil()\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genLearnInit() string {
	if len(g.learnDefs) == 0 {
		return ""
	}
	var b strings.Builder
	b.WriteString("func init() {\n")
	for _, ls := range g.learnDefs {
		for i := range ls.Methods {
			m := &ls.Methods[i]
			fmt.Fprintf(&b, "\tmeow.RegisterMethod(%q, %q, meow_method_%s_%s)\n",
				ls.TypeName, m.Name, ls.TypeName, m.Name)
		}
	}
	b.WriteString("}\n")
	return b.String()
}

func (g *Generator) genPatternCond(subject string, pattern ast.Pattern) string {
	switch p := pattern.(type) {
	case *ast.LiteralPattern:
		return fmt.Sprintf("meow.MatchValue(%s, %s)", subject, g.genExpr(p.Value))
	case *ast.RangePattern:
		low := p.Low.(*ast.IntLit).Value
		high := p.High.(*ast.IntLit).Value
		return fmt.Sprintf("meow.MatchRange(%s, %d, %d)", subject, low, high)
	case *ast.WildcardPattern:
		return "true"
	default:
		return "true"
	}
}

package codegen

import (
	"fmt"
	"sort"
	"strings"

	"github.com/135yshr/meow/pkg/ast"
	"github.com/135yshr/meow/pkg/checker"
	"github.com/135yshr/meow/pkg/mutation"
	"github.com/135yshr/meow/pkg/token"
	"github.com/135yshr/meow/pkg/types"
)

// Generator produces Go source code from a Meow AST.
type Generator struct {
	funcs         []string
	topLevel      []string
	indent        int
	imports       map[string]string // meow pkg name → Go import path
	testMode      bool
	testFuncs     []string // names of test_ prefixed functions
	catwalkFuncs  []string // names of catwalk_ prefixed functions
	catwalkOutput CatwalkOutput
	mutations     map[ast.Expr][]mutation.MutationEntry
	coverEnabled  bool
	coverFilename string
	coverBlocks   []coverBlock
	typeInfo      *checker.TypeInfo
	currentReturnType types.Type // return type of the function currently being generated
	kittyDefs     map[string]*ast.KittyStmt
	collarDefs    map[string]*ast.CollarStmt
	learnDefs     []*ast.LearnStmt
	inLearnMethod  bool              // true when generating a learn method body
	aliasToPackage map[string]string // alias → real package name
	packageToAlias map[string]string // real package name → alias
}

type coverBlock struct {
	startLine, startCol, endLine, endCol, numStmt int
}

var stdPackages = map[string]string{
	"file":    "github.com/135yshr/meow/runtime/file",
	"http":    "github.com/135yshr/meow/runtime/http",
	"testing": "github.com/135yshr/meow/runtime/testing",
}

// resolveImportName resolves name to a real package name, considering aliases.
// Returns (realPkg, true) if the name refers to an imported package,
// or ("", false) if it does not.
func (g *Generator) resolveImportName(name string) (string, bool) {
	if rp, isAlias := g.aliasToPackage[name]; isAlias {
		return rp, true
	}
	if _, imported := g.imports[name]; imported {
		if _, hasAlias := g.packageToAlias[name]; !hasAlias {
			return name, true
		}
		return "", false
	}
	return "", false
}

// capitalizeFirst returns s with its first byte uppercased.
// Returns s unchanged if s is empty.
func capitalizeFirst(s string) string {
	if s == "" {
		return s
	}
	return strings.ToUpper(s[:1]) + s[1:]
}

// New creates a new code generator.
func New() *Generator {
	return &Generator{}
}

// NewTest creates a code generator in test mode.
func NewTest() *Generator {
	return &Generator{testMode: true}
}

// SetTypeInfo stores type checking results for use in code generation.
func (g *Generator) SetTypeInfo(ti *checker.TypeInfo) {
	g.typeInfo = ti
}

// SetCatwalkOutput sets the expected output map for catwalk_ functions.
func (g *Generator) SetCatwalkOutput(co CatwalkOutput) {
	g.catwalkOutput = co
}

// SetMutations sets the mutation schema for schemata-based mutation testing.
func (g *Generator) SetMutations(m map[ast.Expr][]mutation.MutationEntry) {
	g.mutations = m
}

// EnableCoverage activates statement coverage instrumentation.
func (g *Generator) EnableCoverage(filename string) {
	g.coverEnabled = true
	g.coverFilename = filename
}

// Generate produces Go source code from a Program AST.
func (g *Generator) Generate(prog *ast.Program) (string, error) {
	g.collectKittyDefs(prog)
	for _, stmt := range prog.Stmts {
		switch stmt.(type) {
		case *ast.KittyStmt, *ast.BreedStmt, *ast.CollarStmt, *ast.TrickStmt:
			continue
		}
		if ls, ok := stmt.(*ast.LearnStmt); ok {
			g.learnDefs = append(g.learnDefs, ls)
			for i := range ls.Methods {
				g.funcs = append(g.funcs, g.genLearnMethod(ls.TypeName, &ls.Methods[i]))
			}
			continue
		}
		if fn, ok := stmt.(*ast.FuncStmt); ok {
			g.funcs = append(g.funcs, g.genFuncDecl(fn))
		} else {
			code, err := g.genStmtOrError(stmt)
			if err != nil {
				return "", err
			}
			if code != "" {
				g.topLevel = append(g.topLevel, code)
			}
		}
	}
	return g.emit(), nil
}

// GenerateTest produces Go source code from a Program AST in test mode.
// It auto-imports the testing package and wraps test_ functions with Run/Report
// and catwalk_ functions with Catwalk.
func (g *Generator) GenerateTest(prog *ast.Program) (string, error) {
	g.collectKittyDefs(prog)
	for _, stmt := range prog.Stmts {
		switch stmt.(type) {
		case *ast.KittyStmt, *ast.BreedStmt, *ast.CollarStmt, *ast.TrickStmt:
			continue
		}
		if ls, ok := stmt.(*ast.LearnStmt); ok {
			g.learnDefs = append(g.learnDefs, ls)
			for i := range ls.Methods {
				g.funcs = append(g.funcs, g.genLearnMethod(ls.TypeName, &ls.Methods[i]))
			}
			continue
		}
		if fn, ok := stmt.(*ast.FuncStmt); ok {
			g.funcs = append(g.funcs, g.genFuncDecl(fn))
			if strings.HasPrefix(fn.Name, "test_") {
				if len(fn.Params) != 0 {
					return "", fmt.Errorf("test function %s must not take parameters", fn.Name)
				}
				g.testFuncs = append(g.testFuncs, fn.Name)
			} else if strings.HasPrefix(fn.Name, "catwalk_") {
				if len(fn.Params) != 0 {
					return "", fmt.Errorf("catwalk function %s must not take parameters", fn.Name)
				}
				if g.catwalkOutput != nil {
					if _, ok := g.catwalkOutput[fn.Name]; !ok {
						return "", fmt.Errorf("catwalk function %s has no # Output: block", fn.Name)
					}
				}
				g.catwalkFuncs = append(g.catwalkFuncs, fn.Name)
			}
		} else {
			code, err := g.genStmtOrError(stmt)
			if err != nil {
				return "", err
			}
			if code != "" {
				g.topLevel = append(g.topLevel, code)
			}
		}
	}
	g.ensureImport("testing")
	return g.emitTest(), nil
}

func (g *Generator) emitTest() string {
	var b strings.Builder
	b.WriteString("// Code generated by meow compiler. DO NOT EDIT.\n")
	b.WriteString("package main\n\n")
	b.WriteString("import meow \"github.com/135yshr/meow/runtime/meowrt\"\n")
	needsOS := g.coverEnabled || len(g.mutations) > 0
	if needsOS {
		b.WriteString("import \"os\"\n")
	}
	if len(g.mutations) > 0 {
		b.WriteString("import \"strconv\"\n")
	}
	if g.coverEnabled {
		b.WriteString("import meow_coverage \"github.com/135yshr/meow/runtime/coverage\"\n")
	}
	names := make([]string, 0, len(g.imports))
	for name := range g.imports {
		names = append(names, name)
	}
	sort.Strings(names)
	for _, name := range names {
		fmt.Fprintf(&b, "import meow_%s \"%s\"\n", name, g.imports[name])
	}
	b.WriteString("\n")

	if len(g.mutations) > 0 {
		b.WriteString("var __mutant int = -1\n\n")
	}

	needsInit := g.coverEnabled || len(g.mutations) > 0
	if needsInit {
		b.WriteString("func init() {\n")
		if len(g.mutations) > 0 {
			b.WriteString("\tif s := os.Getenv(\"MEOW_MUTANT\"); s != \"\" {\n")
			b.WriteString("\t\tif v, err := strconv.Atoi(s); err == nil {\n")
			b.WriteString("\t\t\t__mutant = v\n")
			b.WriteString("\t\t}\n")
			b.WriteString("\t}\n")
		}
		if g.coverEnabled {
			for i, cb := range g.coverBlocks {
				fmt.Fprintf(&b, "\tmeow_coverage.Register(%q, %d, %d, %d, %d, %d) // block %d\n",
					g.coverFilename, cb.startLine, cb.startCol, cb.endLine, cb.endCol, cb.numStmt, i)
			}
		}
		b.WriteString("}\n\n")
	}

	if initCode := g.genLearnInit(); initCode != "" {
		b.WriteString(initCode)
		b.WriteString("\n")
	}

	for _, fn := range g.funcs {
		b.WriteString(fn)
		b.WriteString("\n\n")
	}

	b.WriteString("func main() {\n")
	for _, line := range g.topLevel {
		b.WriteString("\t")
		b.WriteString(line)
		b.WriteString("\n")
	}
	for _, name := range g.testFuncs {
		fmt.Fprintf(&b, "\tmeow_testing.Run(meow.NewString(%q), meow.NewFunc(%q, func(args ...meow.Value) meow.Value {\n", name, name)
		fmt.Fprintf(&b, "\t\treturn %s()\n", name)
		fmt.Fprintf(&b, "\t}))\n")
	}
	for _, name := range g.catwalkFuncs {
		expected := ""
		if g.catwalkOutput != nil {
			expected = g.catwalkOutput[name]
		}
		fmt.Fprintf(&b, "\tmeow_testing.Catwalk(meow.NewString(%q), meow.NewFunc(%q, func(args ...meow.Value) meow.Value {\n", name, name)
		fmt.Fprintf(&b, "\t\treturn %s()\n", name)
		fmt.Fprintf(&b, "\t}), meow.NewString(%q))\n", expected)
	}
	if g.coverEnabled {
		b.WriteString("\tmeow_coverage.Report(os.Stdout)\n")
		b.WriteString("\tif p := os.Getenv(\"MEOW_COVERPROFILE\"); p != \"\" {\n")
		b.WriteString("\t\tmeow_coverage.WriteProfile(p)\n")
		b.WriteString("\t}\n")
	}
	b.WriteString("\tmeow_testing.Report()\n")
	b.WriteString("}\n")
	return b.String()
}

func (g *Generator) ensureImport(name string) {
	if g.imports == nil {
		g.imports = make(map[string]string)
	}
	if _, ok := g.imports[name]; !ok {
		if path, ok := stdPackages[name]; ok {
			g.imports[name] = path
		}
	}
}

func (g *Generator) needsMeowImport() bool {
	if len(g.topLevel) > 0 {
		return true
	}
	for _, fn := range g.funcs {
		if strings.Contains(fn, "meow.") {
			return true
		}
	}
	return false
}

func (g *Generator) emit() string {
	var b strings.Builder
	b.WriteString("// Code generated by meow compiler. DO NOT EDIT.\n")
	b.WriteString("package main\n\n")
	if g.needsMeowImport() {
		b.WriteString("import meow \"github.com/135yshr/meow/runtime/meowrt\"\n")
	}
	if len(g.mutations) > 0 {
		b.WriteString("import \"os\"\n")
		b.WriteString("import \"strconv\"\n")
	}
	names := make([]string, 0, len(g.imports))
	for name := range g.imports {
		names = append(names, name)
	}
	sort.Strings(names)
	for _, name := range names {
		fmt.Fprintf(&b, "import meow_%s \"%s\"\n", name, g.imports[name])
	}
	b.WriteString("\n")

	if len(g.mutations) > 0 {
		b.WriteString("var __mutant int = -1\n\n")
		b.WriteString("func init() {\n")
		b.WriteString("\tif s := os.Getenv(\"MEOW_MUTANT\"); s != \"\" {\n")
		b.WriteString("\t\tif v, err := strconv.Atoi(s); err == nil {\n")
		b.WriteString("\t\t\t__mutant = v\n")
		b.WriteString("\t\t}\n")
		b.WriteString("\t}\n")
		b.WriteString("}\n\n")
	}

	if initCode := g.genLearnInit(); initCode != "" {
		b.WriteString(initCode)
		b.WriteString("\n")
	}

	for _, fn := range g.funcs {
		b.WriteString(fn)
		b.WriteString("\n\n")
	}

	b.WriteString("func main() {\n")
	for _, line := range g.topLevel {
		b.WriteString("\t")
		b.WriteString(line)
		b.WriteString("\n")
	}
	b.WriteString("}\n")
	return b.String()
}

func (g *Generator) genFuncDecl(fn *ast.FuncStmt) string {
	if g.isFullyTypedFunc(fn) {
		return g.genTypedFuncDecl(fn)
	}
	var b strings.Builder
	params := make([]string, len(fn.Params))
	for i, p := range fn.Params {
		params[i] = p.Name + " meow.Value"
	}
	fmt.Fprintf(&b, "func %s(%s) meow.Value {\n", fn.Name, strings.Join(params, ", "))
	for _, stmt := range fn.Body {
		b.WriteString("\t")
		b.WriteString(g.genStmt(stmt))
		b.WriteString("\n")
	}
	if !g.blockAlwaysReturns(fn.Body) {
		b.WriteString("\treturn meow.NewNil()\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) isFullyTypedFunc(fn *ast.FuncStmt) bool {
	if g.typeInfo == nil {
		return false
	}
	ft, ok := g.typeInfo.FuncTypes[fn.Name]
	if !ok {
		return false
	}
	return isFullyTypedFuncType(ft)
}

func (g *Generator) genTypedFuncDecl(fn *ast.FuncStmt) string {
	ft := g.typeInfo.FuncTypes[fn.Name]
	prevReturnType := g.currentReturnType
	g.currentReturnType = ft.Return
	defer func() { g.currentReturnType = prevReturnType }()
	var b strings.Builder
	params := make([]string, len(fn.Params))
	for i, p := range fn.Params {
		params[i] = p.Name + " " + goTypeString(ft.Params[i])
	}
	fmt.Fprintf(&b, "func %s(%s) %s {\n", fn.Name, strings.Join(params, ", "), goTypeString(ft.Return))
	for _, stmt := range fn.Body {
		b.WriteString("\t")
		b.WriteString(g.genTypedStmt(stmt))
		b.WriteString("\n")
	}
	b.WriteString("}")
	return b.String()
}

func goTypeString(t types.Type) string {
	switch t := t.(type) {
	case types.IntType:
		return "int64"
	case types.FloatType:
		return "float64"
	case types.StringType:
		return "string"
	case types.BoolType:
		return "bool"
	case types.AliasType:
		return goTypeString(t.Underlying)
	default:
		return "meow.Value"
	}
}

func (g *Generator) genTypedStmt(stmt ast.Stmt) string {
	switch s := stmt.(type) {
	case *ast.VarStmt:
		return g.genTypedVarStmt(s)
	case *ast.ReturnStmt:
		return g.genTypedReturnStmt(s)
	case *ast.ExprStmt:
		return g.genTypedExprStmt(s)
	case *ast.IfStmt:
		return g.genTypedIf(s)
	case *ast.RangeStmt:
		return g.genTypedRange(s)
	default:
		return g.genStmt(stmt)
	}
}

func (g *Generator) genTypedVarStmt(s *ast.VarStmt) string {
	t := g.getExprType(s.Value)
	if t != nil && !types.IsAny(t) {
		return fmt.Sprintf("var %s %s = %s", s.Name, goTypeString(t), g.genTypedExpr(s.Value))
	}
	return fmt.Sprintf("var %s meow.Value = %s", s.Name, g.genExpr(s.Value))
}

func (g *Generator) genTypedReturnStmt(s *ast.ReturnStmt) string {
	if s.Value == nil {
		return "return"
	}
	t := g.getExprType(s.Value)
	if t != nil && !types.IsAny(t) {
		return fmt.Sprintf("return %s", g.genTypedExpr(s.Value))
	}
	// Expression is AnyType (e.g. match expression) but function has a concrete return type.
	// Generate the expression with typed boxing, then unbox the meow.Value result.
	exprCode := g.genTypedExpr(s.Value)
	if g.currentReturnType != nil && !types.IsAny(g.currentReturnType) {
		return fmt.Sprintf("return %s", unboxToNative(exprCode, g.currentReturnType))
	}
	return fmt.Sprintf("return %s", exprCode)
}

func (g *Generator) genTypedExprStmt(s *ast.ExprStmt) string {
	if call, ok := s.Expr.(*ast.CallExpr); ok {
		return g.genTypedCall(call)
	}
	return g.genExpr(s.Expr)
}

func (g *Generator) genTypedIf(s *ast.IfStmt) string {
	var b strings.Builder
	condType := g.getExprType(s.Condition)
	if condType != nil && !types.IsAny(condType) {
		fmt.Fprintf(&b, "if %s {\n", g.genTypedExpr(s.Condition))
	} else {
		fmt.Fprintf(&b, "if (%s).IsTruthy() {\n", g.genExpr(s.Condition))
	}
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genTypedStmt(stmt))
		b.WriteString("\n")
	}
	if len(s.ElseBody) > 0 {
		b.WriteString("} else {\n")
		for _, stmt := range s.ElseBody {
			b.WriteString("\t")
			b.WriteString(g.genTypedStmt(stmt))
			b.WriteString("\n")
		}
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genTypedRange(s *ast.RangeStmt) string {
	endType := g.getExprType(s.End)
	if endType != nil {
		endType = types.Unwrap(endType)
	}
	if _, ok := endType.(types.StringType); ok && s.Start == nil && !s.Inclusive {
		return g.genTypedStringRange(s)
	}
	var b strings.Builder
	cmp := "<"
	if s.Inclusive {
		cmp = "<="
	}
	startCode := "int64(0)"
	if s.Start != nil {
		startType := g.getExprType(s.Start)
		if startType != nil && !types.IsAny(startType) {
			startCode = g.genTypedExpr(s.Start)
		} else {
			startCode = ""
		}
	}
	if startCode != "" && endType != nil && !types.IsAny(endType) {
		fmt.Fprintf(&b, "for %s := %s; %s %s %s; %s++ {\n",
			s.Var, startCode, s.Var, cmp, g.genTypedExpr(s.End), s.Var)
	} else {
		startExpr := "meow.NewInt(0)"
		if s.Start != nil {
			startExpr = g.boxValue(s.Start)
		}
		fmt.Fprintf(&b, "for __i := meow.AsInt(%s); __i %s meow.AsInt(%s); __i++ {\n",
			startExpr, cmp, g.boxValue(s.End))
		fmt.Fprintf(&b, "\tvar %s int64 = __i\n", s.Var)
	}
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genTypedStmt(stmt))
		b.WriteString("\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genTypedStringRange(s *ast.RangeStmt) string {
	var b strings.Builder
	if s.IndexVar != "" {
		fmt.Fprintf(&b, "for __idx, __r := range []rune(%s) {\n",
			g.genTypedExpr(s.End))
		fmt.Fprintf(&b, "\t%s := int64(__idx)\n", s.IndexVar)
		fmt.Fprintf(&b, "\tvar %s string = string(__r)\n", s.Var)
		fmt.Fprintf(&b, "\t_ = %s\n\t_ = %s\n", s.IndexVar, s.Var)
	} else {
		fmt.Fprintf(&b, "for _, __r := range []rune(%s) {\n",
			g.genTypedExpr(s.End))
		fmt.Fprintf(&b, "\tvar %s string = string(__r)\n", s.Var)
		fmt.Fprintf(&b, "\t_ = %s\n", s.Var)
	}
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genTypedStmt(stmt))
		b.WriteString("\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) getExprType(expr ast.Expr) types.Type {
	if g.typeInfo == nil {
		return nil
	}
	return g.typeInfo.ExprTypes[expr]
}

func (g *Generator) genTypedExpr(expr ast.Expr) string {
	t := g.getExprType(expr)
	// Handle match expressions specially: they always produce meow.Value
	// but may contain typed variables that need boxing.
	if _, isMatch := expr.(*ast.MatchExpr); isMatch {
		matchCode := g.genTypedMatch(expr.(*ast.MatchExpr))
		if t != nil && isNativeType(t) {
			return unboxToNative(matchCode, t)
		}
		return matchCode
	}
	if t == nil || types.IsAny(t) {
		return g.genExprBoxed(expr)
	}
	switch e := expr.(type) {
	case *ast.IntLit:
		return fmt.Sprintf("int64(%d)", e.Value)
	case *ast.FloatLit:
		return fmt.Sprintf("float64(%g)", e.Value)
	case *ast.StringLit:
		return fmt.Sprintf("%q", e.Value)
	case *ast.BoolLit:
		if e.Value {
			return "true"
		}
		return "false"
	case *ast.Ident:
		return e.Name
	case *ast.UnaryExpr:
		return g.genTypedUnary(e)
	case *ast.BinaryExpr:
		return g.genTypedBinary(e)
	case *ast.CallExpr:
		return g.genTypedCall(e)
	default:
		return g.genExprBoxed(expr)
	}
}

// genExprBoxed generates an expression in untyped (meow.Value) mode,
// but boxes any typed variables so they can be used as meow.Value.
func (g *Generator) genExprBoxed(expr ast.Expr) string {
	if ident, ok := expr.(*ast.Ident); ok {
		t := g.getExprType(expr)
		if t != nil && !types.IsAny(t) {
			return g.boxNative(ident.Name, t)
		}
	}
	return g.genExpr(expr)
}

// boxNative wraps a native Go value in its meow.Value constructor.
func (g *Generator) boxNative(name string, t types.Type) string {
	switch types.Unwrap(t).(type) {
	case types.IntType:
		return fmt.Sprintf("meow.NewInt(%s)", name)
	case types.FloatType:
		return fmt.Sprintf("meow.NewFloat(%s)", name)
	case types.StringType:
		return fmt.Sprintf("meow.NewString(%s)", name)
	case types.BoolType:
		return fmt.Sprintf("meow.NewBool(%s)", name)
	default:
		return name
	}
}

// genTypedMatch generates a match expression where the subject may be a native type.
// It boxes the subject to meow.Value and returns the match result as meow.Value.
func (g *Generator) genTypedMatch(e *ast.MatchExpr) string {
	var b strings.Builder
	subject := g.boxValue(e.Subject)
	b.WriteString(fmt.Sprintf("func() meow.Value {\n\t__subject := %s\n", subject))
	hasCondArm := false
	for i, arm := range e.Arms {
		if _, ok := arm.Pattern.(*ast.WildcardPattern); ok {
			if hasCondArm {
				b.WriteString("\t} else {\n")
				b.WriteString(fmt.Sprintf("\t\treturn %s\n", g.boxValue(arm.Body)))
				b.WriteString("\t}\n")
			} else {
				b.WriteString(fmt.Sprintf("\treturn %s\n", g.boxValue(arm.Body)))
			}
			b.WriteString("\treturn meow.NewNil()\n}()")
			return b.String()
		}
		keyword := "if"
		if i > 0 {
			keyword = "} else if"
		}
		hasCondArm = true
		b.WriteString(fmt.Sprintf("\t%s %s {\n", keyword, g.genPatternCond("__subject", arm.Pattern)))
		b.WriteString(fmt.Sprintf("\t\treturn %s\n", g.boxValue(arm.Body)))
	}
	if hasCondArm {
		b.WriteString("\t}\n")
	}
	b.WriteString("\treturn meow.NewNil()\n}()")
	return b.String()
}

func (g *Generator) genTypedUnary(e *ast.UnaryExpr) string {
	switch e.Op {
	case token.MINUS:
		return fmt.Sprintf("(-%s)", g.genTypedExpr(e.Right))
	case token.NOT:
		if _, ok := g.getExprType(e.Right).(types.BoolType); ok {
			return fmt.Sprintf("(!%s)", g.genTypedExpr(e.Right))
		}
		return fmt.Sprintf("(!(%s).IsTruthy())", g.boxValue(e.Right))
	}
	return g.genUnary(e)
}

func (g *Generator) genTypedBinary(e *ast.BinaryExpr) string {
	left := g.genTypedExpr(e.Left)
	right := g.genTypedExpr(e.Right)
	switch e.Op {
	case token.PLUS:
		return fmt.Sprintf("(%s + %s)", left, right)
	case token.MINUS:
		return fmt.Sprintf("(%s - %s)", left, right)
	case token.STAR:
		return fmt.Sprintf("(%s * %s)", left, right)
	case token.SLASH:
		return fmt.Sprintf("(%s / %s)", left, right)
	case token.PERCENT:
		return fmt.Sprintf("(%s %% %s)", left, right)
	case token.EQ:
		return fmt.Sprintf("(%s == %s)", left, right)
	case token.NEQ:
		return fmt.Sprintf("(%s != %s)", left, right)
	case token.LT:
		return fmt.Sprintf("(%s < %s)", left, right)
	case token.GT:
		return fmt.Sprintf("(%s > %s)", left, right)
	case token.LTE:
		return fmt.Sprintf("(%s <= %s)", left, right)
	case token.GTE:
		return fmt.Sprintf("(%s >= %s)", left, right)
	case token.AND:
		return fmt.Sprintf("(%s && %s)", left, right)
	case token.OR:
		return fmt.Sprintf("(%s || %s)", left, right)
	}
	return g.genBinary(e)
}

func (g *Generator) genTypedCall(e *ast.CallExpr) string {
	// Handle method calls on learn types: unbox dispatch result if typed
	if member, ok := e.Fn.(*ast.MemberExpr); ok {
		call := g.genMemberCall(member, e.Args)
		if t := g.getExprType(e); t != nil && !types.IsAny(t) && isNativeType(t) {
			return unboxToNative(call, t)
		}
		return call
	}

	ident, isIdent := e.Fn.(*ast.Ident)
	if !isIdent {
		return g.genCall(e)
	}

	// Builtin functions that need boxing
	switch ident.Name {
	case "nya":
		args := make([]string, len(e.Args))
		for i, a := range e.Args {
			args[i] = g.boxValue(a)
		}
		return fmt.Sprintf("meow.Nya(%s)", strings.Join(args, ", "))
	case "hiss":
		args := make([]string, len(e.Args))
		for i, a := range e.Args {
			args[i] = g.boxValue(a)
		}
		return fmt.Sprintf("meow.Hiss(%s)", strings.Join(args, ", "))
	case "judge", "expect", "refuse":
		g.ensureImport("testing")
		fn := capitalizeFirst(ident.Name)
		args := make([]string, len(e.Args))
		for i, a := range e.Args {
			args[i] = g.boxValue(a)
		}
		return fmt.Sprintf("meow_testing.%s(%s)", fn, strings.Join(args, ", "))
	case "to_string", "to_int", "to_float", "to_bytes", "is_furball", "gag", "len",
		"head", "tail", "append", "lick", "picky", "curl":
		builtinNames := map[string]string{
			"to_string":  "ToString",
			"to_int":     "ToInt",
			"to_float":   "ToFloat",
			"is_furball":  "IsFurball",
			"gag":        "Gag",
			"len":        "Len",
			"head":       "Head",
			"tail":       "Tail",
			"append":     "Append",
			"lick":       "Lick",
			"picky":      "Picky",
			"curl":       "Curl",
		}
		// Known return types for builtins that produce typed results
		builtinRetTypes := map[string]types.Type{
			"to_string":  types.StringType{},
			"to_int":     types.IntType{},
			"to_float":   types.FloatType{},
			"is_furball":  types.BoolType{},
			"len":        types.IntType{},
		}
		args := make([]string, len(e.Args))
		for i, a := range e.Args {
			args[i] = g.boxValue(a)
		}
		call := fmt.Sprintf("meow.%s(%s)", builtinNames[ident.Name], strings.Join(args, ", "))
		// If the builtin has a known return type and we're in a typed context, unbox
		if retType, ok := builtinRetTypes[ident.Name]; ok {
			return unboxToNative(call, retType)
		}
		return call
	}

	// Collar constructors
	if _, ok := g.collarDefs[ident.Name]; ok {
		args := make([]string, len(e.Args))
		for i, a := range e.Args {
			args[i] = g.boxValue(a)
		}
		return fmt.Sprintf("meow.NewKitty(%q, []string{\"value\"}, %s)",
			ident.Name, strings.Join(args, ", "))
	}

	// Typed user-defined functions (only for fully native signatures)
	if ft, ok := g.typeInfo.FuncTypes[ident.Name]; ok {
		if len(e.Args) < len(ft.Params) {
			return g.genPartialCall(ident.Name, ft, e.Args)
		}
		if isFullyTypedFuncType(ft) {
			args := make([]string, len(e.Args))
			for i, a := range e.Args {
				args[i] = g.genTypedExpr(a)
			}
			return fmt.Sprintf("%s(%s)", ident.Name, strings.Join(args, ", "))
		}
	}

	return g.genCall(e)
}

func (g *Generator) boxValue(expr ast.Expr) string {
	t := g.getExprType(expr)
	if t == nil || types.IsAny(t) {
		return g.genExpr(expr)
	}
	typed := g.genTypedExpr(expr)
	switch types.Unwrap(t).(type) {
	case types.IntType:
		return fmt.Sprintf("meow.NewInt(%s)", typed)
	case types.FloatType:
		return fmt.Sprintf("meow.NewFloat(%s)", typed)
	case types.StringType:
		return fmt.Sprintf("meow.NewString(%s)", typed)
	case types.BoolType:
		return fmt.Sprintf("meow.NewBool(%s)", typed)
	default:
		return g.genExpr(expr)
	}
}

// isNativeType reports whether t maps to a native Go type (int64, float64, string, bool).
// ListType, FurballType, and AnyType are NOT native types; they use meow.Value.
func isNativeType(t types.Type) bool {
	switch t.(type) {
	case types.IntType, types.FloatType, types.StringType, types.BoolType:
		return true
	case types.AliasType:
		return isNativeType(types.Unwrap(t))
	}
	return false
}

func isFullyTypedFuncType(ft types.FuncType) bool {
	if !isNativeType(ft.Return) {
		return false
	}
	for _, p := range ft.Params {
		if !isNativeType(p) {
			return false
		}
	}
	return true
}

func isLiteralExpr(expr ast.Expr) bool {
	switch e := expr.(type) {
	case *ast.IntLit, *ast.FloatLit, *ast.StringLit, *ast.BoolLit:
		return true
	case *ast.UnaryExpr:
		return isLiteralExpr(e.Right)
	default:
		return false
	}
}

func unboxToNative(boxedExpr string, targetType types.Type) string {
	switch types.Unwrap(targetType).(type) {
	case types.IntType:
		return fmt.Sprintf("meow.AsInt(%s)", boxedExpr)
	case types.FloatType:
		return fmt.Sprintf("meow.AsFloat(%s)", boxedExpr)
	case types.StringType:
		return fmt.Sprintf("meow.AsString(%s)", boxedExpr)
	case types.BoolType:
		return fmt.Sprintf("meow.AsBool(%s)", boxedExpr)
	default:
		return boxedExpr
	}
}

func boxNativeCall(call string, retType types.Type) string {
	switch types.Unwrap(retType).(type) {
	case types.IntType:
		return fmt.Sprintf("meow.NewInt(%s)", call)
	case types.FloatType:
		return fmt.Sprintf("meow.NewFloat(%s)", call)
	case types.StringType:
		return fmt.Sprintf("meow.NewString(%s)", call)
	case types.BoolType:
		return fmt.Sprintf("meow.NewBool(%s)", call)
	default:
		return call
	}
}

func (g *Generator) blockAlwaysReturns(stmts []ast.Stmt) bool {
	if len(stmts) == 0 {
		return false
	}
	switch s := stmts[len(stmts)-1].(type) {
	case *ast.ReturnStmt:
		return true
	case *ast.IfStmt:
		return g.blockAlwaysReturns(s.Body) && g.blockAlwaysReturns(s.ElseBody)
	default:
		return false
	}
}

func (g *Generator) genStmt(stmt ast.Stmt) string {
	code := g.genStmtInner(stmt)
	if !g.coverEnabled {
		return code
	}
	pos := stmt.Pos()
	endLine, endCol := g.estimateEndPos(stmt)
	id := len(g.coverBlocks)
	g.coverBlocks = append(g.coverBlocks, coverBlock{pos.Line, pos.Column, endLine, endCol, 1})
	return fmt.Sprintf("meow_coverage.Hit(%d)\n%s", id, code)
}

func (g *Generator) genStmtInner(stmt ast.Stmt) string {
	switch s := stmt.(type) {
	case *ast.VarStmt:
		return fmt.Sprintf("var %s meow.Value = %s", s.Name, g.genExpr(s.Value))
	case *ast.ReturnStmt:
		if s.Value != nil {
			return fmt.Sprintf("return %s", g.genExpr(s.Value))
		}
		return "return meow.NewNil()"
	case *ast.ExprStmt:
		return g.genExpr(s.Expr)
	case *ast.IfStmt:
		return g.genIf(s)
	case *ast.RangeStmt:
		return g.genRange(s)
	default:
		return fmt.Sprintf("/* unsupported stmt: %T */", stmt)
	}
}

func (g *Generator) estimateEndPos(stmt ast.Stmt) (int, int) {
	pos := stmt.Pos()
	switch s := stmt.(type) {
	case *ast.IfStmt:
		body := s.ElseBody
		if len(body) == 0 {
			body = s.Body
		}
		if len(body) > 0 {
			last := body[len(body)-1]
			endLine, _ := g.estimateEndPos(last)
			return endLine + 1, 1
		}
		return pos.Line + 1, 1
	case *ast.RangeStmt:
		if len(s.Body) > 0 {
			last := s.Body[len(s.Body)-1]
			endLine, _ := g.estimateEndPos(last)
			return endLine + 1, 1
		}
		return pos.Line + 1, 1
	default:
		return pos.Line, pos.Column + 1
	}
}

func (g *Generator) collectKittyDefs(prog *ast.Program) {
	g.kittyDefs = make(map[string]*ast.KittyStmt)
	g.collarDefs = make(map[string]*ast.CollarStmt)
	for _, stmt := range prog.Stmts {
		if ks, ok := stmt.(*ast.KittyStmt); ok {
			g.kittyDefs[ks.Name] = ks
		}
		if cs, ok := stmt.(*ast.CollarStmt); ok {
			g.collarDefs[cs.Name] = cs
		}
	}
}

func (g *Generator) genStmtOrError(stmt ast.Stmt) (string, error) {
	switch stmt.(type) {
	case *ast.KittyStmt, *ast.BreedStmt, *ast.CollarStmt, *ast.TrickStmt, *ast.LearnStmt:
		return "", nil
	}
	if s, ok := stmt.(*ast.FetchStmt); ok {
		path, ok := stdPackages[s.Path]
		if !ok {
			return "", fmt.Errorf("unknown package: %s", s.Path)
		}
		if g.imports == nil {
			g.imports = make(map[string]string)
		}
		g.imports[s.Path] = path
		if s.Alias != "" {
			if g.aliasToPackage == nil {
				g.aliasToPackage = make(map[string]string)
			}
			if g.packageToAlias == nil {
				g.packageToAlias = make(map[string]string)
			}
			g.aliasToPackage[s.Alias] = s.Path
			g.packageToAlias[s.Path] = s.Alias
		}
		return "", nil
	}
	return g.genStmt(stmt), nil
}

func (g *Generator) genIf(s *ast.IfStmt) string {
	var b strings.Builder
	fmt.Fprintf(&b, "if (%s).IsTruthy() {\n", g.genExpr(s.Condition))
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genStmt(stmt))
		b.WriteString("\n")
	}
	if len(s.ElseBody) > 0 {
		b.WriteString("} else {\n")
		for _, stmt := range s.ElseBody {
			b.WriteString("\t")
			b.WriteString(g.genStmt(stmt))
			b.WriteString("\n")
		}
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genRange(s *ast.RangeStmt) string {
	endType := g.getExprType(s.End)
	if endType != nil {
		endType = types.Unwrap(endType)
	}
	if _, ok := endType.(types.StringType); ok && s.Start == nil && !s.Inclusive {
		return g.genStringRange(s)
	}
	var b strings.Builder
	cmp := "<"
	if s.Inclusive {
		cmp = "<="
	}
	startExpr := "meow.NewInt(0)"
	if s.Start != nil {
		startExpr = g.genExpr(s.Start)
	}
	fmt.Fprintf(&b, "for __i := meow.AsInt(%s); __i %s meow.AsInt(%s); __i++ {\n",
		startExpr, cmp, g.genExpr(s.End))
	fmt.Fprintf(&b, "\tvar %s meow.Value = meow.NewInt(__i)\n", s.Var)
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genStmt(stmt))
		b.WriteString("\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genStringRange(s *ast.RangeStmt) string {
	var b strings.Builder
	if s.IndexVar != "" {
		fmt.Fprintf(&b, "for __idx, __r := range []rune(meow.AsString(%s)) {\n",
			g.genExpr(s.End))
		fmt.Fprintf(&b, "\tvar %s meow.Value = meow.NewInt(int64(__idx))\n", s.IndexVar)
		fmt.Fprintf(&b, "\tvar %s meow.Value = meow.NewString(string(__r))\n", s.Var)
		fmt.Fprintf(&b, "\t_ = %s\n\t_ = %s\n", s.IndexVar, s.Var)
	} else {
		fmt.Fprintf(&b, "for _, __r := range []rune(meow.AsString(%s)) {\n",
			g.genExpr(s.End))
		fmt.Fprintf(&b, "\tvar %s meow.Value = meow.NewString(string(__r))\n", s.Var)
		fmt.Fprintf(&b, "\t_ = %s\n", s.Var)
	}
	for _, stmt := range s.Body {
		b.WriteString("\t")
		b.WriteString(g.genStmt(stmt))
		b.WriteString("\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genExpr(expr ast.Expr) string {
	if entries, ok := g.mutations[expr]; ok && len(entries) > 0 {
		return g.genMutatedExpr(expr, entries)
	}
	switch e := expr.(type) {
	case *ast.IntLit:
		return fmt.Sprintf("meow.NewInt(%d)", e.Value)
	case *ast.FloatLit:
		return fmt.Sprintf("meow.NewFloat(%g)", e.Value)
	case *ast.StringLit:
		return fmt.Sprintf("meow.NewString(%q)", e.Value)
	case *ast.BoolLit:
		if e.Value {
			return "meow.NewBool(true)"
		}
		return "meow.NewBool(false)"
	case *ast.NilLit:
		return "meow.NewNil()"
	case *ast.Ident:
		return g.genIdent(e)
	case *ast.UnaryExpr:
		return g.genUnary(e)
	case *ast.BinaryExpr:
		return g.genBinary(e)
	case *ast.CallExpr:
		return g.genCall(e)
	case *ast.LambdaExpr:
		return g.genLambda(e)
	case *ast.ListLit:
		return g.genList(e)
	case *ast.IndexExpr:
		return g.genIndex(e)
	case *ast.PipeExpr:
		return g.genPipe(e)
	case *ast.CatchExpr:
		return g.genCatch(e)
	case *ast.MapLit:
		return g.genMap(e)
	case *ast.MatchExpr:
		return g.genMatch(e)
	case *ast.SelfExpr:
		return "self"
	case *ast.MemberExpr:
		// Check if this is a self.field access in a learn method
		if _, isSelf := e.Object.(*ast.SelfExpr); isSelf {
			if e.Member == "value" {
				return "self.(*meow.Kitty).GetField(\"value\")"
			}
			return fmt.Sprintf("self.(*meow.Kitty).GetField(%q)", e.Member)
		}
		obj, ok := e.Object.(*ast.Ident)
		if ok {
			if realPkg, ok := g.resolveImportName(obj.Name); ok {
				return fmt.Sprintf("meow_%s.%s", realPkg, capitalizeFirst(e.Member))
			}
			return fmt.Sprintf("%s.(*meow.Kitty).GetField(%q)", obj.Name, e.Member)
		}
		return fmt.Sprintf("(%s).(*meow.Kitty).GetField(%q)", g.genExpr(e.Object), e.Member)
	default:
		return fmt.Sprintf("/* unsupported expr: %T */", expr)
	}
}

func (g *Generator) genIdent(e *ast.Ident) string {
	return e.Name
}

func (g *Generator) genUnary(e *ast.UnaryExpr) string {
	switch e.Op {
	case token.MINUS:
		return fmt.Sprintf("meow.Negate(%s)", g.genExpr(e.Right))
	case token.NOT:
		return fmt.Sprintf("meow.Not(%s)", g.genExpr(e.Right))
	default:
		return fmt.Sprintf("/* unsupported unary: %v */", e.Op)
	}
}

func (g *Generator) genBinary(e *ast.BinaryExpr) string {
	l := g.genExpr(e.Left)
	r := g.genExpr(e.Right)
	switch e.Op {
	case token.PLUS:
		return fmt.Sprintf("meow.Add(%s, %s)", l, r)
	case token.MINUS:
		return fmt.Sprintf("meow.Sub(%s, %s)", l, r)
	case token.STAR:
		return fmt.Sprintf("meow.Mul(%s, %s)", l, r)
	case token.SLASH:
		return fmt.Sprintf("meow.Div(%s, %s)", l, r)
	case token.PERCENT:
		return fmt.Sprintf("meow.Mod(%s, %s)", l, r)
	case token.EQ:
		return fmt.Sprintf("meow.Equal(%s, %s)", l, r)
	case token.NEQ:
		return fmt.Sprintf("meow.NotEqual(%s, %s)", l, r)
	case token.LT:
		return fmt.Sprintf("meow.LessThan(%s, %s)", l, r)
	case token.GT:
		return fmt.Sprintf("meow.GreaterThan(%s, %s)", l, r)
	case token.LTE:
		return fmt.Sprintf("meow.LessEqual(%s, %s)", l, r)
	case token.GTE:
		return fmt.Sprintf("meow.GreaterEqual(%s, %s)", l, r)
	case token.AND:
		return fmt.Sprintf("meow.And(%s, %s)", l, r)
	case token.OR:
		return fmt.Sprintf("meow.Or(%s, %s)", l, r)
	default:
		return fmt.Sprintf("/* unsupported op: %v */", e.Op)
	}
}

func (g *Generator) genCall(e *ast.CallExpr) string {
	if member, ok := e.Fn.(*ast.MemberExpr); ok {
		return g.genMemberCall(member, e.Args)
	}
	ident, isIdent := e.Fn.(*ast.Ident)
	args := make([]string, len(e.Args))
	for i, a := range e.Args {
		args[i] = g.genExpr(a)
	}
	argStr := strings.Join(args, ", ")

	if isIdent {
		switch ident.Name {
		case "nya":
			return fmt.Sprintf("meow.Nya(%s)", argStr)
		case "hiss":
			return fmt.Sprintf("meow.Hiss(%s)", argStr)
		case "lick":
			return fmt.Sprintf("meow.Lick(%s)", argStr)
		case "picky":
			return fmt.Sprintf("meow.Picky(%s)", argStr)
		case "curl":
			return fmt.Sprintf("meow.Curl(%s)", argStr)
		case "len":
			return fmt.Sprintf("meow.Len(%s)", argStr)
		case "head":
			return fmt.Sprintf("meow.Head(%s)", argStr)
		case "tail":
			return fmt.Sprintf("meow.Tail(%s)", argStr)
		case "append":
			return fmt.Sprintf("meow.Append(%s)", argStr)
		case "to_int":
			return fmt.Sprintf("meow.ToInt(%s)", argStr)
		case "to_float":
			return fmt.Sprintf("meow.ToFloat(%s)", argStr)
		case "to_string":
			return fmt.Sprintf("meow.ToString(%s)", argStr)
		case "gag":
			return fmt.Sprintf("meow.Gag(%s)", argStr)
		case "is_furball":
			return fmt.Sprintf("meow.IsFurball(%s)", argStr)
		case "judge":
			g.ensureImport("testing")
			return fmt.Sprintf("meow_testing.Judge(%s)", argStr)
		case "expect":
			g.ensureImport("testing")
			return fmt.Sprintf("meow_testing.Expect(%s)", argStr)
		case "refuse":
			g.ensureImport("testing")
			return fmt.Sprintf("meow_testing.Refuse(%s)", argStr)
		case "seed":
			return "meow.NewNil()"
		default:
			if ks, ok := g.kittyDefs[ident.Name]; ok {
				fieldNames := make([]string, len(ks.Fields))
				for i, f := range ks.Fields {
					fieldNames[i] = fmt.Sprintf("%q", f.Name)
				}
				return fmt.Sprintf("meow.NewKitty(%q, []string{%s}, %s)",
					ident.Name, strings.Join(fieldNames, ", "), argStr)
			}
			if _, ok := g.collarDefs[ident.Name]; ok {
				return fmt.Sprintf("meow.NewKitty(%q, []string{\"value\"}, %s)",
					ident.Name, argStr)
			}
			if g.typeInfo != nil {
				if ft, ok := g.typeInfo.FuncTypes[ident.Name]; ok {
					if len(e.Args) < len(ft.Params) {
						return g.genPartialCall(ident.Name, ft, e.Args)
					}
					if len(e.Args) == len(ft.Params) && isFullyTypedFuncType(ft) {
						nativeArgs := make([]string, len(e.Args))
						for i, a := range e.Args {
							if isLiteralExpr(a) {
								nativeArgs[i] = g.genTypedExpr(a)
							} else {
								nativeArgs[i] = unboxToNative(args[i], ft.Params[i])
							}
						}
						call := fmt.Sprintf("%s(%s)", ident.Name, strings.Join(nativeArgs, ", "))
						return boxNativeCall(call, ft.Return)
					}
				} else {
					// Not in FuncTypes → must be a variable holding a function
					// value (e.g. partial application result or lambda).
					// The checker populates FuncTypes for all `meow` function
					// declarations, so any identifier absent from FuncTypes is
					// a runtime value that requires meow.Call for dispatch.
					if argStr != "" {
						return fmt.Sprintf("meow.Call(%s, %s)", ident.Name, argStr)
					}
					return fmt.Sprintf("meow.Call(%s)", ident.Name)
				}
			}
			return fmt.Sprintf("%s(%s)", ident.Name, argStr)
		}
	}
	return fmt.Sprintf("meow.Call(%s, %s)", g.genExpr(e.Fn), argStr)
}

func (g *Generator) genMemberCall(member *ast.MemberExpr, rawArgs []ast.Expr) string {
	args := make([]string, len(rawArgs))
	for i, a := range rawArgs {
		args[i] = g.genExpr(a)
	}
	argStr := strings.Join(args, ", ")

	// Check if this is a method call on an object that has learn impls
	if g.typeInfo != nil {
		objCode := g.genExpr(member.Object)
		typeName := g.resolveTypeName(member.Object)
		if typeName != "" {
			if methods, ok := g.typeInfo.LearnImpls[typeName]; ok {
				if _, hasMethod := methods[member.Member]; hasMethod {
					if argStr != "" {
						return fmt.Sprintf("meow.DispatchMethod(%s, %q, %s)", objCode, member.Member, argStr)
					}
					return fmt.Sprintf("meow.DispatchMethod(%s, %q)", objCode, member.Member)
				}
			}
		}
	}

	obj, ok := member.Object.(*ast.Ident)
	if !ok {
		if argStr == "" {
			return fmt.Sprintf("meow.Call((%s).(*meow.Kitty).GetField(%q))",
				g.genExpr(member.Object), member.Member)
		}
		return fmt.Sprintf("meow.Call((%s).(*meow.Kitty).GetField(%q), %s)",
			g.genExpr(member.Object), member.Member, argStr)
	}
	if realPkg, ok := g.resolveImportName(obj.Name); ok {
		return fmt.Sprintf("meow_%s.%s(%s)", realPkg, capitalizeFirst(member.Member), argStr)
	}
	if argStr == "" {
		return fmt.Sprintf("meow.Call(%s.(*meow.Kitty).GetField(%q))",
			obj.Name, member.Member)
	}
	return fmt.Sprintf("meow.Call(%s.(*meow.Kitty).GetField(%q), %s)",
		obj.Name, member.Member, argStr)
}

// resolveTypeName tries to determine the type name for a given expression.
func (g *Generator) resolveTypeName(expr ast.Expr) string {
	if g.typeInfo == nil {
		return ""
	}
	t := g.typeInfo.ExprTypes[expr]
	if t == nil {
		return ""
	}
	t = types.Unwrap(t)
	switch tt := t.(type) {
	case types.KittyType:
		return tt.Name
	case types.CollarType:
		return tt.Name
	}
	return ""
}

func (g *Generator) genPartialCall(fnName string, ft types.FuncType, suppliedArgs []ast.Expr) string {
	remaining := len(ft.Params) - len(suppliedArgs)

	if isFullyTypedFuncType(ft) {
		// Typed function: generate native-typed partial application
		var captureLines []string
		for i, a := range suppliedArgs {
			captureLines = append(captureLines,
				fmt.Sprintf("__c%d := %s", i, g.genTypedExpr(a)))
		}
		var callArgs []string
		for i := range suppliedArgs {
			callArgs = append(callArgs, fmt.Sprintf("__c%d", i))
		}
		for i := range remaining {
			callArgs = append(callArgs,
				fmt.Sprintf("%s", unboxToNative(fmt.Sprintf("args[%d]", i), ft.Params[len(suppliedArgs)+i])))
		}
		call := fmt.Sprintf("%s(%s)", fnName, strings.Join(callArgs, ", "))
		boxed := boxNativeCall(call, ft.Return)

		capture := strings.Join(captureLines, "\n\t")
		if capture != "" {
			capture += "\n\t"
		}
		return fmt.Sprintf("func() meow.Value {\n"+
			"\t%sreturn meow.NewFuncWithArity(%q, %d, func(args ...meow.Value) meow.Value {\n"+
			"\t\treturn %s\n"+
			"\t})\n"+
			"}()", capture, fnName, remaining, boxed)
	}

	// Untyped function: box arguments to ensure meow.Value
	var captureLines []string
	for i, a := range suppliedArgs {
		captureLines = append(captureLines,
			fmt.Sprintf("__c%d := %s", i, g.boxValue(a)))
	}
	var callArgs []string
	for i := range suppliedArgs {
		callArgs = append(callArgs, fmt.Sprintf("__c%d", i))
	}
	for i := range remaining {
		callArgs = append(callArgs, fmt.Sprintf("args[%d]", i))
	}
	call := fmt.Sprintf("%s(%s)", fnName, strings.Join(callArgs, ", "))

	capture := strings.Join(captureLines, "\n\t")
	if capture != "" {
		capture += "\n\t"
	}
	return fmt.Sprintf("func() meow.Value {\n"+
		"\t%sreturn meow.NewFuncWithArity(%q, %d, func(args ...meow.Value) meow.Value {\n"+
		"\t\treturn %s\n"+
		"\t})\n"+
		"}()", capture, fnName, remaining, call)
}

func (g *Generator) genLambda(e *ast.LambdaExpr) string {
	body := g.genExpr(e.Body)
	return fmt.Sprintf("meow.NewFuncWithArity(\"lambda\", %d, func(args ...meow.Value) meow.Value {\n"+
		"\t%s\n"+
		"\treturn %s\n"+
		"})", len(e.Params), g.genLambdaParamBindings(e.Params), body)
}

func (g *Generator) genLambdaParamBindings(params []ast.Param) string {
	var lines []string
	for i, p := range params {
		lines = append(lines, fmt.Sprintf("%s := args[%d]", p.Name, i))
		lines = append(lines, fmt.Sprintf("_ = %s", p.Name))
	}
	return strings.Join(lines, "\n\t")
}

func (g *Generator) genList(e *ast.ListLit) string {
	items := make([]string, len(e.Items))
	for i, item := range e.Items {
		items[i] = g.genExpr(item)
	}
	return fmt.Sprintf("meow.NewList(%s)", strings.Join(items, ", "))
}

func (g *Generator) genMap(e *ast.MapLit) string {
	if len(e.Keys) == 0 {
		return "meow.NewMap(map[string]meow.Value{})"
	}
	entries := make([]string, len(e.Keys))
	for i := range e.Keys {
		key, ok := e.Keys[i].(*ast.StringLit)
		if !ok {
			entries[i] = fmt.Sprintf("/* unsupported map key: %T */", e.Keys[i])
			continue
		}
		entries[i] = fmt.Sprintf("%q: %s", key.Value, g.genExpr(e.Vals[i]))
	}
	return fmt.Sprintf("meow.NewMap(map[string]meow.Value{%s})", strings.Join(entries, ", "))
}

func (g *Generator) genIndex(e *ast.IndexExpr) string {
	return fmt.Sprintf("%s.(*meow.List).Get(int(%s.(*meow.Int).Val))", g.genExpr(e.Left), g.genExpr(e.Index))
}

func (g *Generator) genPipe(e *ast.PipeExpr) string {
	var fn ast.Expr
	var args []ast.Expr

	if call, ok := e.Right.(*ast.CallExpr); ok {
		fn = call.Fn
		args = make([]ast.Expr, 0, len(call.Args)+1)
		args = append(args, e.Left)
		args = append(args, call.Args...)
	} else {
		fn = e.Right
		args = []ast.Expr{e.Left}
	}

	return g.genCall(&ast.CallExpr{Token: e.Token, Fn: fn, Args: args})
}

func (g *Generator) genCatch(e *ast.CatchExpr) string {
	left := g.genExpr(e.Left)
	right := g.genExpr(e.Right)
	return fmt.Sprintf(
		"meow.GagOr(meow.NewFunc(\"~>\", func(args ...meow.Value) meow.Value {\n"+
			"\treturn %s\n"+
			"}), %s)", left, right)
}

func (g *Generator) genMatch(e *ast.MatchExpr) string {
	var b strings.Builder
	subject := g.genExpr(e.Subject)
	b.WriteString(fmt.Sprintf("func() meow.Value {\n\t__subject := %s\n", subject))
	hasCondArm := false
	for i, arm := range e.Arms {
		if _, ok := arm.Pattern.(*ast.WildcardPattern); ok {
			if hasCondArm {
				b.WriteString("\t} else {\n")
				b.WriteString(fmt.Sprintf("\t\treturn %s\n", g.genExpr(arm.Body)))
				b.WriteString("\t}\n")
			} else {
				b.WriteString(fmt.Sprintf("\treturn %s\n", g.genExpr(arm.Body)))
			}
			b.WriteString("\treturn meow.NewNil()\n}()")
			return b.String()
		}
		keyword := "if"
		if i > 0 {
			keyword = "} else if"
		}
		hasCondArm = true
		b.WriteString(fmt.Sprintf("\t%s %s {\n", keyword, g.genPatternCond("__subject", arm.Pattern)))
		b.WriteString(fmt.Sprintf("\t\treturn %s\n", g.genExpr(arm.Body)))
	}
	if hasCondArm {
		b.WriteString("\t}\n")
	}
	b.WriteString("\treturn meow.NewNil()\n}()")
	return b.String()
}

func (g *Generator) genMutatedExpr(original ast.Expr, entries []mutation.MutationEntry) string {
	// Remove this expression's entries to avoid self-recursion
	delete(g.mutations, original)

	var b strings.Builder
	b.WriteString("func() meow.Value {\n")

	// Mutation branches: generate without child mutations
	// (each branch represents only its specific mutation, not combinations)
	saved := g.mutations
	g.mutations = nil
	for _, entry := range entries {
		fmt.Fprintf(&b, "\t\tif __mutant == %d { return %s }\n", entry.ID, g.genExpr(entry.Expr))
	}
	g.mutations = saved

	// Default branch: child mutations remain active
	fmt.Fprintf(&b, "\t\treturn %s\n", g.genExpr(original))
	b.WriteString("\t}()")

	// Restore this entry
	g.mutations[original] = entries
	return b.String()
}

func (g *Generator) genLearnMethod(typeName string, fn *ast.FuncStmt) string {
	var b strings.Builder
	methodFuncName := fmt.Sprintf("meow_method_%s_%s", typeName, fn.Name)

	fmt.Fprintf(&b, "func %s(args ...meow.Value) meow.Value {\n", methodFuncName)
	// Arity guard: self + params
	fmt.Fprintf(&b, "\tif len(args) < %d {\n", 1+len(fn.Params))
	b.WriteString("\t\treturn meow.NewNil()\n")
	b.WriteString("\t}\n")
	// Extract self from first argument
	b.WriteString("\tself := args[0]\n")
	b.WriteString("\t_ = self\n")
	// Extract additional params
	for i, p := range fn.Params {
		fmt.Fprintf(&b, "\t%s := args[%d]\n", p.Name, i+1)
		fmt.Fprintf(&b, "\t_ = %s\n", p.Name)
	}

	prevInLearn := g.inLearnMethod
	g.inLearnMethod = true
	for _, stmt := range fn.Body {
		b.WriteString("\t")
		b.WriteString(g.genStmt(stmt))
		b.WriteString("\n")
	}
	g.inLearnMethod = prevInLearn

	if !g.blockAlwaysReturns(fn.Body) {
		b.WriteString("\treturn meow.NewNil()\n")
	}
	b.WriteString("}")
	return b.String()
}

func (g *Generator) genLearnInit() string {
	if len(g.learnDefs) == 0 {
		return ""
	}
	var b strings.Builder
	b.WriteString("func init() {\n")
	for _, ls := range g.learnDefs {
		for i := range ls.Methods {
			m := &ls.Methods[i]
			fmt.Fprintf(&b, "\tmeow.RegisterMethod(%q, %q, meow_method_%s_%s)\n",
				ls.TypeName, m.Name, ls.TypeName, m.Name)
		}
	}
	b.WriteString("}\n")
	return b.String()
}

func (g *Generator) genPatternCond(subject string, pattern ast.Pattern) string {
	switch p := pattern.(type) {
	case *ast.LiteralPattern:
		return fmt.Sprintf("meow.MatchValue(%s, %s)", subject, g.genExpr(p.Value))
	case *ast.RangePattern:
		low := p.Low.(*ast.IntLit).Value
		high := p.High.(*ast.IntLit).Value
		return fmt.Sprintf("meow.MatchRange(%s, %d, %d)", subject, low, high)
	case *ast.WildcardPattern:
		return "true"
	default:
		return "true"
	}
}

package interpreter

import (
	"fmt"
	"io"

	"github.com/135yshr/meow/pkg/ast"
	"github.com/135yshr/meow/pkg/checker"
	"github.com/135yshr/meow/pkg/token"
	"github.com/135yshr/meow/runtime/meowrt"
)

// returnSignal is used to implement bring (return) via panic/recover.
type returnSignal struct {
	Value meowrt.Value
}

// stepLimitExceeded signals that the step limit was reached.
type stepLimitExceeded struct{}

// Interpreter executes a Meow AST directly.
type Interpreter struct {
	globals    *Environment
	typeInfo   *checker.TypeInfo
	output     io.Writer
	kittyDefs  map[string]*ast.KittyStmt
	collarDefs map[string]*ast.CollarStmt
	funcDefs   map[string]*ast.FuncStmt
	stepCount  int64
	stepLimit  int64
}

// New creates a new Interpreter that writes output to w.
func New(w io.Writer) *Interpreter {
	return &Interpreter{
		globals:    NewEnvironment(),
		output:     w,
		kittyDefs:  make(map[string]*ast.KittyStmt),
		collarDefs: make(map[string]*ast.CollarStmt),
		funcDefs:   make(map[string]*ast.FuncStmt),
		stepLimit:  10_000_000,
	}
}

// SetTypeInfo sets the checker type information (optional).
func (interp *Interpreter) SetTypeInfo(ti *checker.TypeInfo) {
	interp.typeInfo = ti
}

// SetStepLimit sets the maximum number of evaluation steps.
func (interp *Interpreter) SetStepLimit(limit int64) {
	interp.stepLimit = limit
}

// RunSafe executes the program and returns any error (including panics).
func (interp *Interpreter) RunSafe(prog *ast.Program) (err error) {
	defer func() {
		if r := recover(); r != nil {
			switch r.(type) {
			case stepLimitExceeded:
				err = fmt.Errorf("Hiss! step limit exceeded (%d steps), nya~", interp.stepLimit)
			default:
				if msg, ok := r.(string); ok {
					err = fmt.Errorf("%s", msg)
				} else {
					err = fmt.Errorf("internal error: %v", r)
				}
			}
		}
	}()
	interp.Run(prog)
	return nil
}

// Run executes the program. Panics propagate to the caller.
func (interp *Interpreter) Run(prog *ast.Program) {
	meowrt.ClearMethods()
	interp.stepCount = 0

	// Pass 1: collect declarations
	for _, stmt := range prog.Stmts {
		switch s := stmt.(type) {
		case *ast.KittyStmt:
			interp.kittyDefs[s.Name] = s
		case *ast.CollarStmt:
			interp.collarDefs[s.Name] = s
		case *ast.FuncStmt:
			interp.registerFunc(s, interp.globals)
		case *ast.LearnStmt:
			interp.registerLearnMethods(s)
		case *ast.BreedStmt, *ast.TrickStmt:
			// type-level declarations, nothing to do at runtime
		}
	}

	// Pass 2: execute top-level statements
	for _, stmt := range prog.Stmts {
		switch stmt.(type) {
		case *ast.KittyStmt, *ast.CollarStmt, *ast.FuncStmt,
			*ast.LearnStmt, *ast.BreedStmt, *ast.TrickStmt:
			continue
		}
		interp.execStmt(stmt, interp.globals)
	}
}

func (interp *Interpreter) checkStep() {
	interp.stepCount++
	if interp.stepCount > interp.stepLimit {
		panic(stepLimitExceeded{})
	}
}

// --- Statement Execution ---

func (interp *Interpreter) execStmt(stmt ast.Stmt, env *Environment) {
	interp.checkStep()
	switch s := stmt.(type) {
	case *ast.VarStmt:
		val := interp.evalExpr(s.Value, env)
		env.Define(s.Name, val)
	case *ast.ExprStmt:
		interp.evalExpr(s.Expr, env)
	case *ast.ReturnStmt:
		var val meowrt.Value
		if s.Value != nil {
			val = interp.evalExpr(s.Value, env)
		} else {
			val = meowrt.NewNil()
		}
		panic(returnSignal{Value: val})
	case *ast.IfStmt:
		interp.execIf(s, env)
	case *ast.RangeStmt:
		interp.execRange(s, env)
	case *ast.FuncStmt:
		// Nested function definition
		interp.registerFunc(s, env)
	case *ast.FetchStmt:
		if s.Alias != "" {
			panic(fmt.Sprintf("Hiss! nab %q tag %s is not supported in the playground, nya~", s.Path, s.Alias))
		}
		panic(fmt.Sprintf("Hiss! nab %q is not supported in the playground, nya~", s.Path))
	default:
		// KittyStmt, CollarStmt, etc. already handled in Pass 1
	}
}

func (interp *Interpreter) execBlock(stmts []ast.Stmt, env *Environment) {
	for _, stmt := range stmts {
		interp.execStmt(stmt, env)
	}
}

func (interp *Interpreter) execIf(s *ast.IfStmt, env *Environment) {
	cond := interp.evalExpr(s.Condition, env)
	if cond.IsTruthy() {
		child := env.Child()
		interp.execBlock(s.Body, child)
	} else if len(s.ElseBody) > 0 {
		child := env.Child()
		interp.execBlock(s.ElseBody, child)
	}
}

func (interp *Interpreter) execRange(s *ast.RangeStmt, env *Environment) {
	endVal := interp.evalExpr(s.End, env)

	// String iteration: purr ch (str) or purr i, ch (str)
	if s.Start == nil && !s.Inclusive {
		if str, ok := endVal.(*meowrt.String); ok {
			for i, r := range []rune(str.Val) {
				interp.checkStep()
				child := env.Child()
				child.Define(s.Var, meowrt.NewString(string(r)))
				if s.IndexVar != "" {
					child.Define(s.IndexVar, meowrt.NewInt(int64(i)))
				}
				interp.execBlock(s.Body, child)
			}
			return
		}
	}

	var start int64
	if s.Start != nil {
		start = meowrt.AsInt(interp.evalExpr(s.Start, env))
	}
	end := meowrt.AsInt(endVal)

	if s.Start == nil {
		// count form: purr i (n) → i = 0..n-1
		for i := int64(0); i < end; i++ {
			interp.checkStep()
			child := env.Child()
			child.Define(s.Var, meowrt.NewInt(i))
			interp.execBlock(s.Body, child)
		}
	} else if s.Inclusive {
		// range form inclusive: purr i (a..b) → i = a..b
		for i := start; i <= end; i++ {
			interp.checkStep()
			child := env.Child()
			child.Define(s.Var, meowrt.NewInt(i))
			interp.execBlock(s.Body, child)
		}
	} else {
		// range form exclusive
		for i := start; i < end; i++ {
			interp.checkStep()
			child := env.Child()
			child.Define(s.Var, meowrt.NewInt(i))
			interp.execBlock(s.Body, child)
		}
	}
}

// --- Function Registration ---

func (interp *Interpreter) registerFunc(fn *ast.FuncStmt, env *Environment) {
	interp.funcDefs[fn.Name] = fn
	captured := env
	fnVal := meowrt.NewFuncWithArity(fn.Name, len(fn.Params), func(args ...meowrt.Value) meowrt.Value {
		return interp.callUserFunc(fn, args, captured)
	})
	env.Define(fn.Name, fnVal)
}

func (interp *Interpreter) callUserFunc(fn *ast.FuncStmt, args []meowrt.Value, closure *Environment) meowrt.Value {
	if len(args) < len(fn.Params) {
		// Partial application: capture supplied args and return a new function
		captured := make([]meowrt.Value, len(args))
		copy(captured, args)
		remaining := len(fn.Params) - len(args)
		return meowrt.NewFuncWithArity(fn.Name, remaining, func(moreArgs ...meowrt.Value) meowrt.Value {
			allArgs := make([]meowrt.Value, 0, len(captured)+len(moreArgs))
			allArgs = append(allArgs, captured...)
			allArgs = append(allArgs, moreArgs...)
			return interp.callUserFunc(fn, allArgs, closure)
		})
	}

	child := closure.Child()
	for i, p := range fn.Params {
		if i < len(args) {
			child.Define(p.Name, args[i])
		} else {
			child.Define(p.Name, meowrt.NewNil())
		}
	}

	var result meowrt.Value
	func() {
		defer func() {
			if r := recover(); r != nil {
				if sig, ok := r.(returnSignal); ok {
					result = sig.Value
				} else {
					panic(r)
				}
			}
		}()
		interp.execBlock(fn.Body, child)
	}()

	if result != nil {
		return result
	}
	return meowrt.NewNil()
}

func (interp *Interpreter) registerLearnMethods(ls *ast.LearnStmt) {
	for i := range ls.Methods {
		m := &ls.Methods[i]
		typeName := ls.TypeName
		method := m
		meowrt.RegisterMethod(typeName, method.Name, func(args ...meowrt.Value) meowrt.Value {
			child := interp.globals.Child()
			if len(args) > 0 {
				child.Define("self", args[0])
			}
			for j, p := range method.Params {
				if j+1 < len(args) {
					child.Define(p.Name, args[j+1])
				} else {
					child.Define(p.Name, meowrt.NewNil())
				}
			}

			var result meowrt.Value
			func() {
				defer func() {
					if r := recover(); r != nil {
						if sig, ok := r.(returnSignal); ok {
							result = sig.Value
						} else {
							panic(r)
						}
					}
				}()
				interp.execBlock(method.Body, child)
			}()

			if result != nil {
				return result
			}
			return meowrt.NewNil()
		})
	}
}

// --- Expression Evaluation ---

func (interp *Interpreter) evalExpr(expr ast.Expr, env *Environment) meowrt.Value {
	interp.checkStep()
	switch e := expr.(type) {
	case *ast.IntLit:
		return meowrt.NewInt(e.Value)
	case *ast.FloatLit:
		return meowrt.NewFloat(e.Value)
	case *ast.StringLit:
		return meowrt.NewString(e.Value)
	case *ast.BoolLit:
		return meowrt.NewBool(e.Value)
	case *ast.NilLit:
		return meowrt.NewNil()
	case *ast.Ident:
		return env.Get(e.Name)
	case *ast.SelfExpr:
		return env.Get("self")
	case *ast.UnaryExpr:
		return interp.evalUnary(e, env)
	case *ast.BinaryExpr:
		return interp.evalBinary(e, env)
	case *ast.CallExpr:
		return interp.evalCall(e, env)
	case *ast.LambdaExpr:
		return interp.evalLambda(e, env)
	case *ast.ListLit:
		return interp.evalList(e, env)
	case *ast.MapLit:
		return interp.evalMap(e, env)
	case *ast.IndexExpr:
		return interp.evalIndex(e, env)
	case *ast.MemberExpr:
		return interp.evalMember(e, env)
	case *ast.PipeExpr:
		return interp.evalPipe(e, env)
	case *ast.CatchExpr:
		return interp.evalCatch(e, env)
	case *ast.MatchExpr:
		return interp.evalMatch(e, env)
	default:
		panic(fmt.Sprintf("Hiss! unsupported expression: %T, nya~", expr))
	}
}

func (interp *Interpreter) evalUnary(e *ast.UnaryExpr, env *Environment) meowrt.Value {
	right := interp.evalExpr(e.Right, env)
	switch e.Op {
	case token.MINUS:
		return meowrt.Negate(right)
	case token.NOT:
		return meowrt.Not(right)
	default:
		panic(fmt.Sprintf("Hiss! unsupported unary operator: %v, nya~", e.Op))
	}
}

func (interp *Interpreter) evalBinary(e *ast.BinaryExpr, env *Environment) meowrt.Value {
	// Short-circuit for AND/OR
	if e.Op == token.AND {
		left := interp.evalExpr(e.Left, env)
		if !left.IsTruthy() {
			return left
		}
		return interp.evalExpr(e.Right, env)
	}
	if e.Op == token.OR {
		left := interp.evalExpr(e.Left, env)
		if left.IsTruthy() {
			return left
		}
		return interp.evalExpr(e.Right, env)
	}

	left := interp.evalExpr(e.Left, env)
	right := interp.evalExpr(e.Right, env)

	switch e.Op {
	case token.PLUS:
		return meowrt.Add(left, right)
	case token.MINUS:
		return meowrt.Sub(left, right)
	case token.STAR:
		return meowrt.Mul(left, right)
	case token.SLASH:
		return meowrt.Div(left, right)
	case token.PERCENT:
		return meowrt.Mod(left, right)
	case token.EQ:
		return meowrt.Equal(left, right)
	case token.NEQ:
		return meowrt.NotEqual(left, right)
	case token.LT:
		return meowrt.LessThan(left, right)
	case token.GT:
		return meowrt.GreaterThan(left, right)
	case token.LTE:
		return meowrt.LessEqual(left, right)
	case token.GTE:
		return meowrt.GreaterEqual(left, right)
	default:
		panic(fmt.Sprintf("Hiss! unsupported binary operator: %v, nya~", e.Op))
	}
}

// --- Builtin Helpers ---

func requireArgs(name string, args []meowrt.Value, count int) {
	if len(args) < count {
		panic(fmt.Sprintf("Hiss! %s requires %d argument(s), got %d, nya~", name, count, len(args)))
	}
}

func (interp *Interpreter) dispatchBuiltin(name string, args []meowrt.Value) (meowrt.Value, bool) {
	switch name {
	case "nya":
		return interp.builtinNya(args), true
	case "hiss":
		return meowrt.Hiss(args...), true
	case "len":
		requireArgs("len", args, 1)
		return meowrt.Len(args[0]), true
	case "to_int":
		requireArgs("to_int", args, 1)
		return meowrt.ToInt(args[0]), true
	case "to_float":
		requireArgs("to_float", args, 1)
		return meowrt.ToFloat(args[0]), true
	case "to_string":
		requireArgs("to_string", args, 1)
		return meowrt.ToString(args[0]), true
	case "gag":
		requireArgs("gag", args, 1)
		return meowrt.Gag(args[0]), true
	case "is_furball":
		requireArgs("is_furball", args, 1)
		return meowrt.IsFurball(args[0]), true
	case "head":
		requireArgs("head", args, 1)
		return meowrt.Head(args[0]), true
	case "tail":
		requireArgs("tail", args, 1)
		return meowrt.Tail(args[0]), true
	case "append":
		requireArgs("append", args, 2)
		return meowrt.Append(args[0], args[1]), true
	case "lick":
		requireArgs("lick", args, 2)
		return meowrt.Lick(args[0], args[1]), true
	case "picky":
		requireArgs("picky", args, 2)
		return meowrt.Picky(args[0], args[1]), true
	case "curl":
		requireArgs("curl", args, 3)
		return meowrt.Curl(args[0], args[1], args[2]), true
	default:
		return nil, false
	}
}

// --- Call Expression ---

func (interp *Interpreter) evalCall(e *ast.CallExpr, env *Environment) meowrt.Value {
	// Handle member calls (method dispatch and stdlib)
	if member, ok := e.Fn.(*ast.MemberExpr); ok {
		return interp.evalMemberCall(member, e.Args, env)
	}

	// Evaluate arguments
	args := make([]meowrt.Value, len(e.Args))
	for i, a := range e.Args {
		args[i] = interp.evalExpr(a, env)
	}

	// Identifier-based calls
	if ident, ok := e.Fn.(*ast.Ident); ok {
		// Builtins
		if val, ok := interp.dispatchBuiltin(ident.Name, args); ok {
			return val
		}

		// Kitty constructor
		if ks, ok := interp.kittyDefs[ident.Name]; ok {
			fieldNames := make([]string, len(ks.Fields))
			for i, f := range ks.Fields {
				fieldNames[i] = f.Name
			}
			return meowrt.NewKitty(ident.Name, fieldNames, args...)
		}

		// Collar constructor
		if _, ok := interp.collarDefs[ident.Name]; ok {
			return meowrt.NewKitty(ident.Name, []string{"value"}, args...)
		}

		// User-defined function (looked up from environment)
		if env.Has(ident.Name) {
			fnVal := env.Get(ident.Name)
			if fn, ok := fnVal.(*meowrt.Func); ok {
				return meowrt.Call(fn, args...)
			}
			panic(fmt.Sprintf("Hiss! %s is not callable, nya~", ident.Name))
		}

		panic(fmt.Sprintf("Hiss! undefined function %s, nya~", ident.Name))
	}

	// First-class function call (e.g. variable holding a Func)
	fnVal := interp.evalExpr(e.Fn, env)
	if fn, ok := fnVal.(*meowrt.Func); ok {
		return meowrt.Call(fn, args...)
	}
	panic(fmt.Sprintf("Hiss! %s is not callable, nya~", fnVal.Type()))
}

func (interp *Interpreter) evalMemberCall(member *ast.MemberExpr, rawArgs []ast.Expr, env *Environment) meowrt.Value {
	args := make([]meowrt.Value, len(rawArgs))
	for i, a := range rawArgs {
		args[i] = interp.evalExpr(a, env)
	}

	obj := interp.evalExpr(member.Object, env)

	// Method dispatch via registry
	if k, ok := obj.(*meowrt.Kitty); ok {
		if _, found := meowrt.LookupMethod(k.TypeName, member.Member); found {
			return meowrt.DispatchMethod(obj, member.Member, args...)
		}
		// Kitty field that is a function
		field := k.GetField(member.Member)
		if fn, ok := field.(*meowrt.Func); ok {
			return meowrt.Call(fn, args...)
		}
		panic(fmt.Sprintf("Hiss! %s.%s is not callable, nya~", k.TypeName, member.Member))
	}

	panic(fmt.Sprintf("Hiss! cannot call method %s on %s, nya~", member.Member, obj.Type()))
}

// --- Lambda ---

func (interp *Interpreter) evalLambda(e *ast.LambdaExpr, env *Environment) meowrt.Value {
	captured := env
	arity := len(e.Params)
	evalWithArgs := func(args []meowrt.Value) meowrt.Value {
		child := captured.Child()
		for i, p := range e.Params {
			if i < len(args) {
				child.Define(p.Name, args[i])
			} else {
				child.Define(p.Name, meowrt.NewNil())
			}
		}
		return interp.evalExpr(e.Body, child)
	}
	return meowrt.NewFuncWithArity("lambda", arity, func(args ...meowrt.Value) meowrt.Value {
		if len(args) < arity {
			return meowrt.PartialApply(
				meowrt.NewFuncWithArity("lambda", arity, func(allArgs ...meowrt.Value) meowrt.Value {
					return evalWithArgs(allArgs)
				}),
				args...,
			)
		}
		return evalWithArgs(args)
	})
}

// --- Collections ---

func (interp *Interpreter) evalList(e *ast.ListLit, env *Environment) meowrt.Value {
	items := make([]meowrt.Value, len(e.Items))
	for i, item := range e.Items {
		items[i] = interp.evalExpr(item, env)
	}
	return meowrt.NewList(items...)
}

func (interp *Interpreter) evalMap(e *ast.MapLit, env *Environment) meowrt.Value {
	items := make(map[string]meowrt.Value, len(e.Keys))
	for i := range e.Keys {
		key := interp.evalExpr(e.Keys[i], env)
		val := interp.evalExpr(e.Vals[i], env)
		items[meowrt.AsString(key)] = val
	}
	return meowrt.NewMap(items)
}

func (interp *Interpreter) evalIndex(e *ast.IndexExpr, env *Environment) meowrt.Value {
	left := interp.evalExpr(e.Left, env)
	index := interp.evalExpr(e.Index, env)

	switch obj := left.(type) {
	case *meowrt.List:
		return obj.Get(int(meowrt.AsInt(index)))
	case *meowrt.Map:
		key := meowrt.AsString(index)
		if v, ok := obj.Get(key); ok {
			return v
		}
		return meowrt.NewNil()
	default:
		panic(fmt.Sprintf("Hiss! cannot index %s, nya~", left.Type()))
	}
}

// --- Member Access ---

func (interp *Interpreter) evalMember(e *ast.MemberExpr, env *Environment) meowrt.Value {
	obj := interp.evalExpr(e.Object, env)
	if k, ok := obj.(*meowrt.Kitty); ok {
		return k.GetField(e.Member)
	}
	panic(fmt.Sprintf("Hiss! cannot access field %s on %s, nya~", e.Member, obj.Type()))
}

// --- Pipe ---

func (interp *Interpreter) evalPipe(e *ast.PipeExpr, env *Environment) meowrt.Value {
	left := interp.evalExpr(e.Left, env)

	// x |=| f(y) → f(x, y)
	if call, ok := e.Right.(*ast.CallExpr); ok {
		args := make([]meowrt.Value, 0, len(call.Args)+1)
		args = append(args, left)
		for _, a := range call.Args {
			args = append(args, interp.evalExpr(a, env))
		}

		// Handle member call
		if member, ok := call.Fn.(*ast.MemberExpr); ok {
			obj := interp.evalExpr(member.Object, env)
			if k, ok := obj.(*meowrt.Kitty); ok {
				if _, found := meowrt.LookupMethod(k.TypeName, member.Member); found {
					return meowrt.DispatchMethod(obj, member.Member, args...)
				}
			}
		}

		// Handle ident call
		if ident, ok := call.Fn.(*ast.Ident); ok {
			return interp.evalCallByName(ident.Name, args, env)
		}

		fnVal := interp.evalExpr(call.Fn, env)
		if fn, ok := fnVal.(*meowrt.Func); ok {
			return meowrt.Call(fn, args...)
		}
		panic(fmt.Sprintf("Hiss! pipe target is not callable, nya~"))
	}

	// x |=| f → f(x)
	fnVal := interp.evalExpr(e.Right, env)
	if fn, ok := fnVal.(*meowrt.Func); ok {
		return meowrt.Call(fn, left)
	}
	panic(fmt.Sprintf("Hiss! pipe target is not callable, nya~"))
}

func (interp *Interpreter) evalCallByName(name string, args []meowrt.Value, env *Environment) meowrt.Value {
	if val, ok := interp.dispatchBuiltin(name, args); ok {
		return val
	}

	if env.Has(name) {
		fnVal := env.Get(name)
		if fn, ok := fnVal.(*meowrt.Func); ok {
			return meowrt.Call(fn, args...)
		}
	}

	// Kitty constructor
	if ks, ok := interp.kittyDefs[name]; ok {
		fieldNames := make([]string, len(ks.Fields))
		for i, f := range ks.Fields {
			fieldNames[i] = f.Name
		}
		return meowrt.NewKitty(name, fieldNames, args...)
	}

	// Collar constructor
	if _, ok := interp.collarDefs[name]; ok {
		return meowrt.NewKitty(name, []string{"value"}, args...)
	}

	panic(fmt.Sprintf("Hiss! undefined function %s, nya~", name))
}

// --- Catch ---

func (interp *Interpreter) evalCatch(e *ast.CatchExpr, env *Environment) meowrt.Value {
	// Wrap left side in a thunk
	thunk := meowrt.NewFunc("~>", func(args ...meowrt.Value) meowrt.Value {
		return interp.evalExpr(e.Left, env)
	})
	fallback := interp.evalExpr(e.Right, env)
	return meowrt.GagOr(thunk, fallback)
}

// --- Pattern Match ---

func (interp *Interpreter) evalMatch(e *ast.MatchExpr, env *Environment) meowrt.Value {
	subject := interp.evalExpr(e.Subject, env)
	for _, arm := range e.Arms {
		if interp.matchPattern(subject, arm.Pattern, env) {
			return interp.evalExpr(arm.Body, env)
		}
	}
	return meowrt.NewNil()
}

func (interp *Interpreter) matchPattern(subject meowrt.Value, pattern ast.Pattern, env *Environment) bool {
	switch p := pattern.(type) {
	case *ast.WildcardPattern:
		return true
	case *ast.LiteralPattern:
		patternVal := interp.evalExpr(p.Value, env)
		return meowrt.MatchValue(subject, patternVal)
	case *ast.RangePattern:
		lowLit, lowOk := p.Low.(*ast.IntLit)
		highLit, highOk := p.High.(*ast.IntLit)
		if !lowOk || !highOk {
			return false
		}
		return meowrt.MatchRange(subject, lowLit.Value, highLit.Value)
	default:
		return false
	}
}

// --- Builtin nya (output capture) ---

func (interp *Interpreter) builtinNya(args []meowrt.Value) meowrt.Value {
	parts := make([]string, len(args))
	for i, v := range args {
		parts[i] = v.String()
	}
	for i, p := range parts {
		if i > 0 {
			fmt.Fprint(interp.output, " ")
		}
		fmt.Fprint(interp.output, p)
	}
	fmt.Fprintln(interp.output)
	return meowrt.NewNil()
}

package meowrt

import (
	"fmt"
	"strings"
)

// Nya prints a value (the Meow print function).
func Nya(args ...Value) Value {
	parts := make([]string, len(args))
	for i, v := range args {
		parts[i] = v.String()
	}
	for i, p := range parts {
		if i > 0 {
			fmt.Print(" ")
		}
		fmt.Print(p)
	}
	fmt.Println()
	return NewNil()
}

// Hiss raises an error with the given message.
func Hiss(args ...Value) Value {
	parts := make([]string, len(args))
	for i, v := range args {
		parts[i] = v.String()
	}
	if len(parts) == 0 {
		panic("Hiss!")
	}
	panic(fmt.Sprintf("Hiss! %s", strings.Join(parts, " ")))
}

// Call invokes a function value with the given arguments.
// If the function has a fixed arity and fewer arguments are supplied,
// it returns a partially applied function.
func Call(fn Value, args ...Value) Value {
	f, ok := fn.(*Func)
	if !ok {
		panic(fmt.Sprintf("Hiss! %s is not callable, nya~", fn.Type()))
	}
	if f.Arity > 0 {
		if len(args) < f.Arity {
			return PartialApply(f, args...)
		}
		if len(args) > f.Arity {
			panic(fmt.Sprintf("Hiss! %s expects %d arguments but got %d, nya~", f.Name, f.Arity, len(args)))
		}
	}
	return f.Call(args...)
}

// Len returns the length of a string or list.
func Len(v Value) Value {
	switch v := v.(type) {
	case *String:
		return NewInt(int64(len(v.Val)))
	case *List:
		return NewInt(int64(v.Len()))
	default:
		panic(fmt.Sprintf("Hiss! Cannot get length of %s, nya~", v.Type()))
	}
}

// ToInt converts a value to an integer.
func ToInt(v Value) Value {
	switch v := v.(type) {
	case *Int:
		return v
	case *Float:
		return NewInt(int64(v.Val))
	case *Bool:
		if v.Val {
			return NewInt(1)
		}
		return NewInt(0)
	default:
		panic(fmt.Sprintf("Hiss! Cannot convert %s to Int, nya~", v.Type()))
	}
}

// ToFloat converts a value to a float.
func ToFloat(v Value) Value {
	switch v := v.(type) {
	case *Float:
		return v
	case *Int:
		return NewFloat(float64(v.Val))
	default:
		panic(fmt.Sprintf("Hiss! Cannot convert %s to Float, nya~", v.Type()))
	}
}

// ToString converts a value to a string.
func ToString(v Value) Value {
	return NewString(v.String())
}

// ToBytes converts a string value to a list of byte integers.
func ToBytes(v Value) Value {
	s, ok := v.(*String)
	if !ok {
		panic(fmt.Sprintf("Hiss! Cannot convert %s to bytes, nya~", v.Type()))
	}
	bytes := []byte(s.Val)
	elems := make([]Value, len(bytes))
	for i, b := range bytes {
		elems[i] = NewInt(int64(b))
	}
	return NewList(elems)
}

// Gag calls fn (a zero-argument Func) and recovers from any panic,
// returning the panic message wrapped in a Furball.
// If fn succeeds, its return value is returned as-is.
func Gag(fn Value) Value {
	f, ok := fn.(*Func)
	if !ok {
		panic(fmt.Sprintf("Hiss! gag expects a function, got %s, nya~", fn.Type()))
	}
	var result Value
	func() {
		defer func() {
			if r := recover(); r != nil {
				result = &Furball{Message: fmt.Sprintf("%v", r)}
			}
		}()
		result = f.Call()
	}()
	return result
}

// GagOr calls fn (a zero-argument Func) and recovers from any panic.
// If the call succeeds, its return value is returned as-is.
// If it panics, the fallback is used: if fallback is a Func it is called
// with the Furball as argument; otherwise fallback is returned directly.
func GagOr(fn Value, fallback Value) Value {
	result := Gag(fn)
	if _, ok := result.(*Furball); ok {
		if f, fok := fallback.(*Func); fok {
			return f.Call(result)
		}
		return fallback
	}
	return result
}

// IsFurball returns NewBool(true) if v is a Furball, NewBool(false) otherwise.
func IsFurball(v Value) Value {
	_, ok := v.(*Furball)
	return NewBool(ok)
}

